INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (100, 5.2, '2026-02-06', 4, 1, 1, 'tt29550683', 'A misfit group of unwitting high school students stumble upon a cursed object, an ancient Aztec Death Whistle. They discover that blowing the whistle and the terrifying sound it emits will summon their future deaths to hunt them down.', 'https://m.media-amazon.com/images/M/MV5BNWIwYzUwNmMtYTY2My00ODg2LWI3MmEtNmY0Njg3MzYwYmQyXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Whistle', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (69, 5.9, '2026-01-01', 7, 4, 4, 'tt38353877', 'They walked into a haunted house with a history of possession and murder. The victims never came out, but the footage did.', 'https://m.media-amazon.com/images/M/MV5BZmM4MzY1OTQtMDhiNy00MzdhLTliNzQtY2QzZTJkMDhjZjlmXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'The House on Haunted Grounds', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (93, 3.8, '2026-04-10', 12, 9, 9, 'tt14500286', 'Merriell Sunday Sr. and Hollis Bannister vanished in Alaska. Ellie and Merriell Jr. mount a search, but an ancient threat stalks their expedition into the wilderness, hunting them as they seek the truth behind the disappearances.', 'https://m.media-amazon.com/images/M/MV5BNDA4OGU1ZjQtNDI3ZS00NGE5LThjOWQtODQ1ZWRkNTY2NDcxXkEyXkFqcGc@._V1_QL75_UY562_CR35,0,380,562_.jpg', 'R', null, 'The Yeti', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (112, 6.5, '2026-03-20', 16, 13, 12, 'tt15574124', 'Tommy Shelby rots in a gilded cage of memory; a shell of a man haunted by the literal ghosts of his kin. He is a ghost himself until a siren call from the past pulls him back to the soot of Small Heath. There, the empire he built is a distorted reflection; led by a son whose ambition is fueled by a jagged cocktail of resentment and abandonment. Duke brokers a deal with a fascist devil, trading national stability for the hollow promise of a father figure. Tommy must weaponize his own ruthless cunning to dismantle the treasonous machine his absence created. The price of his legendary survival is a final, bloody collision with his own flesh.', 'https://m.media-amazon.com/images/M/MV5BNTdlNTNjNjctYTg2MC00NTFlLTliNTctODFiZjZmNWRkYTVlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Peaky Blinders: The Immortal Man', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (94, 6.1, '2026-03-13', 21, 18, 17, 'tt35892608', 'The host of an ''all-things-creepy'' podcast moves into her dying mother''s house to be her primary caregiver. When her podcast is sent 10 audio recordings of a young pregnant couple experiencing paranormal noises, she realizes the woman''s story is a mirror of her own and each new recording scratches at her sanity, drawing her into a fate she cannot escape.', 'https://m.media-amazon.com/images/M/MV5BZDY1YzI5NWUtYTdmYi00N2YyLWJmOWMtYWZiZTY5NTE0MjIxXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Undertone', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (107, 7.6, '2016-11-23', 26, 22, 21, 'tt3521164', 'Moana Waialiki is a sea voyaging enthusiast and the only daughter of a chief in a long line of navigators. When her island''s fishermen can''t catch any fish and the crops fail, she learns that the demigod Maui caused the blight by stealing the heart of the goddess, Te Fiti. The only way to heal the island is to persuade Maui to return Te Fiti''s heart, so Moana sets off on an epic journey across the Pacific. The film is based on stories from Polynesian mythology.', 'https://m.media-amazon.com/images/M/MV5BMjI4MzU5NTExNF5BMl5BanBnXkFtZTgwNzY1MTEwMDI@._V1_SX300.jpg', 'PG', null, 'Moana', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (114, 5.5, '2026-02-27', 29, 28, 26, 'tt27047903', 'When a new Ghostface killer emerges in the town where Sidney Prescott has built a new life, her darkest fears are realized as her daughter becomes the next target.', 'https://m.media-amazon.com/images/M/MV5BMzk2YzRjYmItNTA5Mi00ODczLTljYzUtOWE1ZDFkODhlZWJlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Scream 7', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (142, 9.3, '1994-10-14', 31, 30, 29, 'tt0111161', 'Chronicles the experiences of a formerly successful banker as a prisoner in the gloomy jailhouse of Shawshank after being found guilty of a crime he did not commit. The film portrays the man''s unique way of dealing with his new, torturous life; along the way he befriends a number of fellow prisoners, most notably a wise long-term inmate named Red.', 'https://m.media-amazon.com/images/M/MV5BMDAyY2FhYjctNDc5OS00MDNlLThiMGUtY2UxYWVkNGY2ZjljXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'The Shawshank Redemption', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (109, 7, '2006-06-30', 38, 37, 34, 'tt0458352', 'In New York, the simple and naive just-graduated in journalism Andrea Sachs is hired to work as the second assistant of the powerful and sophisticated Miranda Priestly, the ruthless and merciless executive of the Runway fashion magazine. Andrea dreams to become a journalist and faces the opportunity as a temporary professional challenge. The first assistant Emily advises Andrea about the behavior and preferences of their cruel boss, and the stylist Nigel helps Andrea to dress more adequately for the environment. Andrea changes her attitude and behavior, affecting her private life and the relationship with her boyfriend Nate, her family and friends. In the end, Andrea learns that life is made of choices.', 'https://m.media-amazon.com/images/M/MV5BOWM3NTI3YWEtYjJmMy00M2U5LWI1NzEtZWM3ZDY2ZWNjOGRiXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Devil Wears Prada', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (121, 6.1, '2011-06-24', 45, 44, 41, 'tt1855110', 'An inquisitive girl, Vidya falls in love with Mano''s impulsive "do it now or hold it forever" philosophy, without knowing anything about him or where he came from. When she proposes to him, he instinctively decides to flee the city. But destiny stops him. As Vidya travels with him to America, we discover his story, his love, his plight, and his need to live a life of anonymity.', 'https://m.media-amazon.com/images/M/MV5BMTQ1NDExNTA5Ml5BMl5BanBnXkFtZTcwOTc3MjA2NQ@@._V1_SX300.jpg', 'N/A', null, '180', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (95, 4.6, '2026-02-17', 47, 46, 43, 'tt14507394', 'A drifter, who arrives in a small town, finds residents in the grip of a ruthless boss and tries to free them.', 'https://m.media-amazon.com/images/M/MV5BZDYwZjZiYWItMWVlYi00NzVmLThmNDYtMjQzZDExYzI5ZmQ4XkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Hellfire', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (168, 6.5, '2023-07-28', 51, 50, 47, 'tt14993250', 'A sensual love story between a boy who belongs to rich, upper class family, the heir to Dhanlaxmi Enterprises, lives in a lavish mansion in Gurgaon called House Gurgaon and a middle class girl who lives in a lousy fort. They fall in love with each other but their parents are unhappy of this union.', 'https://m.media-amazon.com/images/M/MV5BYTE2YTZlODgtMTRiNS00YjZkLTljN2YtNTM3ZTQ2MzcwZGNiXkEyXkFqcGc@._V1_SX300.jpg', 'Not Rated', null, 'Rocky Aur Rani Kii Prem Kahaani', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (113, 5.9, '2025-11-14', 54, 53, 50, 'tt4712810', 'The Four Horsemen reunite and team up with a new generation of young illusionists to expose a diamond heiress''s global money laundering scheme for criminals.', 'https://m.media-amazon.com/images/M/MV5BYmZmZDc1Y2EtMmU2MS00NmMzLTllZmYtNjlkODFkNjZlOGE0XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Now You See Me: Now You Don''t', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (106, 4, '2026-01-23', 57, 57, 53, 'tt22868010', 'When James receives a mysterious letter from his lost love Mary, he is drawn to Silent Hill--a once-familiar town now consumed by darkness. As he searches for her, James faces monstrous creatures and unravels a terrifying truth that will push him to the edge of his sanity.', 'https://m.media-amazon.com/images/M/MV5BOWVjYjU0ZTAtNGVlNi00NGM1LTgzZjctNTZjMjAyYTc4N2VlXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'Return to Silent Hill', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (110, 6.9, '2024-12-20', 1, 2, 2, 'tt18259086', 'Sonic, Knuckles, and Tails reunite against a powerful new adversary, Shadow, a mysterious villain with powers unlike anything they have faced before. With their abilities outmatched in every way, Team Sonic must seek out an unlikely alliance in hopes of stopping Shadow and protecting the planet.', 'https://m.media-amazon.com/images/M/MV5BMjZjNjE5NDEtOWJjYS00Mjk2LWI1ZDYtOWI1ZWI3MzRjM2UzXkEyXkFqcGc@._V1_QL75_UX380_CR0,8,380,562_.jpg', 'PG', null, 'Sonic the Hedgehog 3', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (137, 6.3, '1984-12-14', 11, 8, 8, 'tt0087182', 'In the distant year of 10191, all the planets of the known Universe are under the control of Padishah Emperor Shaddam IV and the most important commodity in the Universe is a substance called the spice "MELANGE" which is said to have the power of extending life, expanding the consciousness and even to "fold space" ; being able to travel to any distance without physically moving. This spice "MELANGE" is said to only be produced in the desert planet of Arrakis, where the FREMEN people have the prophecy of a man who will lead them to true freedom. This "desert planet"of Arrakis is also known as DUNE. A secret report of the space "GUILD" talks about some circumstances and plans that could jeopardize the production of "SPICE" with four planets involved: ARRAKIS, CALADAN, GIEDI PRIME and KAITAIN, a world at least visually very alike to Earth and house of the Emperor of the known Universe. The "GUILD" sends a third stage navigator to KAITAIN to ask details from the Emperor and to demand him the killing of young Paul Atreides, son of the Duke Leto Atreides of CALADAN.', 'https://m.media-amazon.com/images/M/MV5BMGJlMGM3NDAtOWNhMy00MWExLWI2MzEtMDQ0ZDIzZDY5ZmQ2XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Dune', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (166, 8.4, '2024-03-01', 22, 19, 18, 'tt15239678', 'Paul Atreides unites with Chani and the Fremen while on a warpath of revenge against the conspirators who destroyed his family. Facing a choice between the love of his life and the fate of the known universe, he endeavors to prevent a terrible future only he can foresee.', 'https://m.media-amazon.com/images/M/MV5BNTc0YmQxMjEtODI5MC00NjFiLTlkMWUtOGQ5NjFmYWUyZGJhXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Dune: Part Two', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (121, 8.6, '1977-05-25', 36, 35, 32, 'tt0076759', 'The Imperial Forces, under orders from cruel Darth Vader, hold Princess Leia hostage in their efforts to quell the rebellion against the Galactic Empire. Luke Skywalker and Han Solo, captain of the Millennium Falcon, work together with the companionable droid duo R2-D2 and C-3PO to rescue the beautiful princess, help the Rebel Alliance and restore freedom and justice to the Galaxy.', 'https://m.media-amazon.com/images/M/MV5BOGUwMDk0Y2MtNjBlNi00NmRiLTk2MWYtMGMyMDlhYmI4ZDBjXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Star Wars: Episode IV - A New Hope', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (89, 4, '2026-02-05', 49, 48, 45, 'tt33479805', 'Follows best friends Maddie and Trish as they find themselves trapped in a remote lagoon with the dangerous killer whale named Ceto.', 'https://m.media-amazon.com/images/M/MV5BMWRhZGE5YTMtMDg4NC00NTFjLTg4MTEtMzA2MmVhM2UxNDdlXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Killer Whale', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (179, 8.8, '2002-12-18', 53, 56, 49, 'tt0167261', 'The continuing quest of Frodo and the Fellowship to destroy the One Ring. Frodo and Sam discover they are being followed by the mysterious Gollum. Aragorn, the Elf archer Legolas, and Gimli the Dwarf encounter the besieged Rohan kingdom, whose once great King Theoden has fallen under Saruman''s deadly spell.', 'https://m.media-amazon.com/images/M/MV5BMGQxMDdiOWUtYjc1Ni00YzM1LWE2NjMtZTg3Y2JkMjEzMTJjXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Lord of the Rings: The Two Towers', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 5.1, '2024-01-18', 66, 65, 60, 'tt30629563', 'A seemingly normal school day ends in unthinkable disaster when a mysterious fire breaks out in the school basement. Chaos, panic and confusion prevail among students and teachers.', 'https://m.media-amazon.com/images/M/MV5BM2QxM2M3NTgtOWRhMi00MWEwLTliMWMtYjFhZTFjYWQzMGI3XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'From the Ashes', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (131, 6.1, '2004-05-07', 75, 76, 70, 'tt0338526', 'Van Helsing is in the world to rid all evil, even if not everyone agrees with him. The Vatican sends the monster hunter and his ally, Carl, to Transylvania. They have been sent to this land to stop the powerful Count Dracula. Whilst there they join forces with a Gypsy Princess called Anna Valerious, who is determined to end an ancient curse on her family by destroying the vampire. They just don''t know how!', 'https://m.media-amazon.com/images/M/MV5BNDk3NTdlYzQtMjhiMy00MWJkLWFjNDctMzE4ZGEwZWExNGViXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Van Helsing', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (92, 8.1, '2001-11-02', 81, 84, 78, 'tt0198781', 'A city of monsters with no humans called Monstropolis centers around the city''s power company, Monsters, Inc. The lovable, confident, tough, furry blue behemoth-like giant monster named James P. Sullivan (better known as Sulley) and his wisecracking best friend, short, green cyclops monster Mike Wazowski, discover what happens when the real world interacts with theirs in the form of a 3-year-old girl dubbed "Boo," who accidentally sneaks into the monster world with Sulley one night. And now it''s up to Sulley and Mike to send Boo back in her door before anybody finds out, especially two evil villains such as Sulley''s main rival as a scarer, chameleon-like Randall (a monster that Boo is very afraid of), who possesses the ability to change the color of his skin, and Mike and Sulley''s boss Mr. Waternoose, the chairman and chief executive officer of Monsters, Inc.', 'https://m.media-amazon.com/images/M/MV5BMTY1NTI0ODUyOF5BMl5BanBnXkFtZTgwNTEyNjQ0MDE@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'G', null, 'Monsters, Inc.', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (98, 8.1, '2010-03-26', 90, 93, 86, 'tt0892769', 'Long ago up North on the Island of Berk, the young Viking, Hiccup, wants to join his town''s fight against the dragons that continually raid their town. However, his macho father and village leader, Stoik the Vast, will not allow his small, clumsy, but inventive son to do so. Regardless, Hiccup ventures out into battle and downs a mysterious Night Fury dragon with his invention, but can''t bring himself to kill it. Instead, Hiccup and the dragon, whom he dubs Toothless, begin a friendship that would open up both their worlds as the observant boy learns that his people have misjudged the species. But even as the two each take flight in their own way, they find that they must fight the destructive ignorance plaguing their world.', 'https://m.media-amazon.com/images/M/MV5BMjA5NDQyMjc2NF5BMl5BanBnXkFtZTcwMjg5ODcyMw@@._V1_SX300.jpg', 'PG', null, 'How to Train Your Dragon', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (169, 7.1, '2025-05-23', 98, 103, 96, 'tt9603208', 'Ethan Hunt and the IMF team continue their search for the terrifying AI known as the Entity - which has infiltrated intelligence networks all over the globe - with the world''s governments and a mysterious ghost from Ethan''s past on their trail. Joined by new allies and armed with the means to shut the Entity down for good, Hunt is in a race against time to prevent the world as we know it from changing forever.', 'https://m.media-amazon.com/images/M/MV5BZGQ5NGEyYTItMjNiMi00Y2EwLTkzOWItMjc5YjJiMjMyNTI0XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Mission: Impossible - The Final Reckoning', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (195, 9, '1994-02-04', 6, 3, 3, 'tt0108052', 'Oskar Schindler is a vain and greedy German businessman who becomes an unlikely humanitarian amid the barbaric German Nazi reign when he feels compelled to turn his factory into a refuge for Jews. Based on the true story of Oskar Schindler who managed to save about 1100 Jews from being gassed at the Auschwitz concentration camp, it is a testament to the good in all of us.', 'https://m.media-amazon.com/images/M/MV5BNjM1ZDQxYWUtMzQyZS00MTE1LWJmZGYtNGUyNTdlYjM3ZmVmXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'Schindler''s List', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 8, '2016-02-12', 8, 5, 5, 'tt1431045', 'This is the origin story of former Special Forces operative turned mercenary Wade Wilson, who after being subjected to a rogue experiment that leaves him with accelerated healing powers, adopts the alter ego Deadpool. Armed with his new abilities and a dark, twisted sense of humor, Deadpool hunts down the man who nearly destroyed his life.', 'https://m.media-amazon.com/images/M/MV5BNzY3ZWU5NGQtOTViNC00ZWVmLTliNjAtNzViNzlkZWQ4YzQ4XkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'Deadpool', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (117, 8.5, '1979-06-22', 9, 6, 6, 'tt0078748', 'In the distant future, the commercial spaceship "Nostromo" crew is on its way home when the crew picks up a distress call from a distant moon. The crew must investigate, and the spaceship descends on the small planetoid afterwards. After a rough landing, three crew members leave the spaceship to explore the area on the planetoid. At the same time, the ship''s computer deciphers the message. When the crew realizes it is not alone on the spaceship, they must deal with the consequences.', 'https://m.media-amazon.com/images/M/MV5BN2NhMDk2MmEtZDQzOC00MmY5LThhYzAtMDdjZGFjOGZjMjdjXkEyXkFqcGc@._V1_QL75_UX380_CR0,6,380,562_.jpg', 'R', null, 'Alien', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (98, 5.2, '2026-01-09', 10, 7, 7, 'tt14850054', 'Greenland sequel. In a continuation of the story, the Garrity family, who survive a near-extinction level event when an interstellar comet hits Earth, must leave the safety of the Greenland bunker and embark on a perilous journey across the decimated frozen wasteland of Europe to find a new home.', 'https://m.media-amazon.com/images/M/MV5BOWEzM2IzZTMtYzA2Yi00NjY0LWE1ODktNTllZmI3ZTI1MzBmXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Greenland 2: Migration', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 4.7, '2025-06-27', 13, 10, 10, 'tt31179712', 'Special Forces commandos are abducted mid-operation by a mysterious spacecraft and, upon awakening, find themselves prey to a relentless alien race in a fight for survival.', 'https://m.media-amazon.com/images/M/MV5BYThkNDg5NTktZjViZC00NzY2LTkxNDItODgzMWIyNGQwZDM4XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Osiris', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 6.2, '2003-03-27', 14, 11, 11, 'tt0363292', 'In Santiago, Chile, the schoolteacher Luisa proposes a debate about sex with the parents of her students with the intention of giving classes about sex education to the youngsters. She is a young independent woman that is split between the love for her young mate, the painter Valentín, and for her experienced lover, the middle-age father of one of her students and successful writer Jorge. Jorge still lives with his wife Mónica, but their marriage ended and they do not even talk to each other, but his affair with Luisa is limited to sex and he doesn''t seem to want a serious relationship. In the meeting, the parents are divided in groups, and Luisa stays with Jorge, and the couples womanizer Álvaro and his pregnant wife Elena and shy butcher Emilio and his frigid wife Maca. Álvaro is a wolf man, harasses all the beautiful women that he meets for one night stand, unfaithful and neglecting his wife at home. When Luisa finds that she is pregnant and Valentin is going to work in São Paulo, she makes a decision with her sentimental life. When Elena meets her former friend from university Carlos, Álvaro becomes jealous and tries to commit with her. When the liberated and independent niece Susan spends a couple of days in his home, the faithful Emilio is seduced by the sexy and gorgeous young girl, while Maca finds her sexuality, reading magazines and going to the gynecologist.', 'https://m.media-amazon.com/images/M/MV5BMTM2MTI4MjY2Ml5BMl5BanBnXkFtZTcwMzAyOTczMQ@@._V1_SX300.jpg', 'N/A', null, 'Sex with Love', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (59, 7.3, '2022-09-08', 15, 12, 4, 'tt21860836', 'A new documentary that showcases the making of the epic limited series. Features never-before-seen, behind-the-scenes footage, interviews and visits to the creature shop and props department.', 'https://m.media-amazon.com/images/M/MV5BNjgzNjY5M2EtNWEzYy00MDg5LWIzYTYtZTY2NDkyZjkxODcyXkEyXkFqcGc@._V1_SX300.jpg', 'TV-14', null, 'Obi-Wan Kenobi: A Jedi''s Return', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (120, 4.2, '2024-02-23', 17, 14, 13, 'tt26861992', 'A criminal defense attorney, unhappy in her marriage, finds herself seduced by her mysterious new client, an artist accused of murdering his girlfriend.', 'https://m.media-amazon.com/images/M/MV5BMmY2OGU4MmItOTg0Zi00NWUyLWI3YjgtOGJlMzFiNWQ5Mjg4XkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'My Fault', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (128, 6.7, '2025-02-14', 18, 15, 14, 'tt13654226', 'Two highly-trained operatives are appointed to posts in guard towers on opposite sides of a vast and highly classified gorge, protecting the world from an undisclosed, mysterious evil that lurks within. They bond from a distance while trying to stay vigilant in defending against an unseen enemy. When the cataclysmic threat to humanity is revealed to them, they must work together in a test of both their physical and mental strength to keep the secret in the gorge before it''s too late.', 'https://m.media-amazon.com/images/M/MV5BOTQ5Y2QyYTktYmFmZi00NWJlLWE0MzgtYTA4M2I0ZjQwZjcxXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'PG-13', null, 'The Gorge', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (113, 6.9, '2026-01-30', 19, 16, 15, 'tt8036976', 'Two work colleagues, Linda Liddle (Rachel McAdams) and her arrogant boss Bradley Preston (Dylan O''Brien), are the only survivors of their company plane crash on a deserted island, forced to rely on one another for food and shelter, as well as confront old resentments and conflicts. As dwindling resources and rising paranoia put them in a psychological strain, they struggle not only to survive the island''s unforgiving brutal environment, but also to navigate an escalating battle of shifting power dynamics filled with dark humor, tension and unexpected twists.', 'https://m.media-amazon.com/images/M/MV5BOTgxOWY5NTMtYjdiNi00NTIyLTkwMTQtMWNjM2IzYTU0ODgyXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Send Help', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (107, 7.2, '2025-11-07', 20, 17, 16, 'tt31227572', 'In the future, on a remote planet, Dek, a young predator recently outcast from his native clan, finds an unlikely ally in Thia. Together, they soon embark on a treacherous and extremely dangerous journey in search of the ultimate adversary.', 'https://m.media-amazon.com/images/M/MV5BNTdjZGUxMTItNjRkNS00N2VhLWE4MjMtMjVhODMwMGIxNjUwXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Predator: Badlands', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (136, 8.7, '1999-03-31', 24, 20, 19, 'tt0133093', 'Thomas A. Anderson is a man living two lives. By day he is an average computer programmer and by night a hacker known as Neo. Neo has always questioned his reality, but the truth is far beyond his imagination. Neo finds himself targeted by the police when he is contacted by Morpheus, a legendary computer hacker branded a terrorist by the government. As a rebel against the machines, Neo must confront the agents: super-powerful computer programs devoted to stopping Neo and the entire human rebellion.', 'https://m.media-amazon.com/images/M/MV5BN2NmN2VhMTQtMDNiOS00NDlhLTliMjgtODE2ZTY0ODQyNDRhXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'The Matrix', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (94, 6.3, '2024-03-08', 23, 21, 20, 'tt21692408', 'After Po is tapped to become the Spiritual Leader of the Valley of Peace, he needs to find and train a new Dragon Warrior, while a wicked sorceress plans to re-summon all the master villains whom Po has vanquished to the spirit re...', 'https://m.media-amazon.com/images/M/MV5BMzJlNGYxYzQtOTg4MC00OTMyLTkwYzMtZDRlNTgwY2YwOWYxXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Kung Fu Panda 4', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (152, 9.1, '2008-07-18', 3, 27, 25, 'tt0468569', 'Set within a year after the events of Batman Begins (2005), Batman, Lieutenant James Gordon, and new District Attorney Harvey Dent successfully begin to round up the criminals that plague Gotham City, until a mysterious and sadistic criminal mastermind known only as "The Joker" appears in Gotham, creating a new wave of chaos. Batman''s struggle against The Joker becomes deeply personal, forcing him to "confront everything he believes" and improve his technology to stop him. A love triangle develops between Bruce Wayne, Dent, and Rachel Dawes.', 'https://m.media-amazon.com/images/M/MV5BMTMxNTMwODM0NF5BMl5BanBnXkFtZTcwODAyMTk2Mw@@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'The Dark Knight', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (106, 6, '1982-12-23', 37, 36, 33, 'tt0083655', 'A monkey like man found in the jungles of Congo is brought to Milan, Italy and is called Bingo Bongo. Only Laura, an anthropologist, believes in his human qualities.', 'https://m.media-amazon.com/images/M/MV5BNWVlZDg2YTYtZGJlNS00NTJlLWFkODYtY2NkMDAzYTgzYTIxXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Bingo Bongo', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (137, 7.5, '2025-04-18', 44, 43, 40, 'tt31193180', '1930s. Brothers "Smoke" and "Stack" Moore return home to Mississippi after working for the Chicago Mafia. They buy a sawmill and a juke joint and use their experience as gangsters to ensure that their businesses flourish. Things appear to be going well but trouble has just hit town, trouble in supernatural form.', 'https://m.media-amazon.com/images/M/MV5BNjIwZWY4ZDEtMmIxZS00NDA4LTg4ZGMtMzUwZTYyNzgxMzk5XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Sinners', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (85, 5.3, '2024-08-06', 52, 51, 48, 'tt27155283', 'Two friends, aspiring YouTubers, trespass where they shouldn''t. Their adventure takes a terrifying turn as they confront an unimaginable horror.', 'https://m.media-amazon.com/images/M/MV5BOTQxMmNhNDItZTY4My00NTBjLWE3ZjgtZTM0OTA5YzJjZjMzXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Do Not Enter', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (132, 8.5, '2019-11-08', 58, 58, 54, 'tt6751668', 'The Kims - mother and father Chung-sook and Ki-taek, and their young adult offspring, son Ki-woo and daughter Ki-jung - are a poor family living in a shabby and cramped half basement apartment in a busy lower working class commercial district of Seoul. Without even knowing it, they, especially Mr. and Mrs. Kim, literally smell of poverty. Often as a collective, they perpetrate minor scams to get by, and even when they have jobs, they do the minimum work required. Ki-woo is the one who has dreams of getting out of poverty by one day going to university. Despite not having that university education, Ki-woo is chosen by his university student friend Min, who is leaving to go to school, to take over his tutoring job to Park Da-hye, who Min plans to date once he returns to Seoul and she herself is in university. The Parks are a wealthy family who for four years have lived in their modernistic house designed by and the former residence of famed architect Namgoong. While Mr. and Mrs. Park are all about status, Mrs. Park has a flighty, simpleminded mentality and temperament, which Min tells Ki-woo to feel comfortable in lying to her about his education to get the job. In getting the job, Ki-woo further learns that Mrs. Park is looking for an art therapist for the Parks'' adolescent son, Da-song, Ki-woo quickly recommending his professional art therapist friend "Jessica", really Ki-jung who he knows can pull off the scam in being the easiest liar of the four Kims. In Ki-woo also falling for Da-hye, he begins to envision himself in that house, and thus the Kims as a collective start a plan for all the Kims, like Ki-jung using assumed names, to replace existing servants in the Parks'' employ in orchestrating reasons for them to be fired. The most difficult to get rid of may be Moon-gwang, the Parks'' housekeeper who literally came with the house - she Namgoong''s housekeeper when he lived there - and thus knows all the little nooks and crannies of it better than the Parks themselves. The question then becomes how far the Kims can take this scam in their quest to become their version of the Parks.', 'https://m.media-amazon.com/images/M/MV5BYjk1Y2U4MjQtY2ZiNS00OWQyLWI3MmYtZWUwNmRjYWRiNWNhXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Parasite', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (140, 7.4, '2010-12-03', 65, 66, 61, 'tt1668191', 'Veteran homicide cop Ferman (Sener Sen) and his hot-headed partner Ydris (Cem Yilmaz) team up with rookie cop and anthropology major Hasan (Okan Yalabik) to investigate the murder of a young woman. The suspects include her conservative family, who might have killed her for honor, her drug-dealing boyfriend and aged billionaire Battal (Çetin Tekindor) who had taken the victim as his second wife.', 'https://m.media-amazon.com/images/M/MV5BMTYzMjkzODk4Nl5BMl5BanBnXkFtZTcwOTYzODQxNA@@._V1_SX300.jpg', 'N/A', null, 'Hunting Season', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 7.4, '2001-02-02', 76, 78, 72, 'tt0213847', 'Malèna is about the peril of a beauty through the eyes of a 12 year old kid named Renato. He experiences three things on the same day, beginning of war, getting a bike and sees the arrival of Malèna in town. Through his eyes, we see the curse of beauty and loneliness of Malena, whose husband is presumed to be dead, and through his soul we see his love for her.', 'https://m.media-amazon.com/images/M/MV5BYjA4MTEyY2YtYjgxYi00ZDkzLTkyZGQtZmRkOGI4M2ZhM2EzXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Malena', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (125, 7.8, '2025-12-05', 80, 83, 77, 'tt14905854', 'In 16th century England, young tutor and writer William Shakespeare meets Agnes and they fall in love. They have three children, two daughters - Susanna and Judith - and a son - Hamnet. Shakespeare''s career as a playwright starts to take off but this tests his relationship with Agnes and his children. Then tragedy strikes.', 'https://m.media-amazon.com/images/M/MV5BMDQ5ZmY0OWYtOTYzZi00Mzg5LWE3N2EtMjYwZTAzZmJhYjkyXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Hamnet', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (139, 7.8, '2006-12-08', 97, 102, 95, 'tt0472043', 'In the Maya civilization, a peaceful tribe is brutally attacked by warriors seeking slaves and human beings for sacrifice for their gods. Jaguar Paw hides his pregnant wife and his son in a deep hole nearby their tribe and is captured while fighting with his people. An eclipse spares his life from the sacrifice and later he has to fight to survive and save his beloved family.', 'https://m.media-amazon.com/images/M/MV5BMzJkNzI3ZmEtZmRhOS00YTM1LWI3OTAtZmVjZmNkODIxNmFmXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Apocalypto', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (178, 8.9, '2001-12-19', 53, 109, 49, 'tt0120737', 'An ancient Ring thought lost for centuries has been found, and through a strange twist of fate has been given to a small Hobbit named Frodo. When Gandalf discovers the Ring is in fact the One Ring of the Dark Lord Sauron, Frodo must make an epic quest to the Cracks of Doom in order to destroy it. However, he does not go alone. He is joined by Gandalf, Legolas the elf, Gimli the Dwarf, Aragorn, Boromir, and his three Hobbit friends Merry, Pippin, and Samwise. Through mountains, snow, darkness, forests, rivers and plains, facing evil and danger at every corner the Fellowship of the Ring must go. Their quest to destroy the One Ring is the only hope for the end of the Dark Lords reign.', 'https://m.media-amazon.com/images/M/MV5BNzIxMDQ2YTctNDY4MC00ZTRhLTk4ODQtMTVlOWY4NTdiYmMwXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Lord of the Rings: The Fellowship of the Ring', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (149, 7.4, '2025-11-07', 108, 119, 110, 'tt1312221', 'Oscar-winning director Guillermo del Toro adapts Mary Shelley''s classic tale of Victor Frankenstein, a brilliant but egotistical scientist who brings a creature to life in a monstrous experiment that ultimately leads to the undoing of both the creator and his tragic creation.', 'https://m.media-amazon.com/images/M/MV5BYzYzNDYxMTQtMTU4OS00MTdlLThhMTQtZjI4NGJmMTZmNmRiXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Frankenstein', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 7.9, '2001-05-18', 25, 23, 22, 'tt0126029', 'When a green ogre named Shrek discovers his swamp has been ''swamped'' with all sorts of fairytale creatures by the scheming Lord Farquaad, Shrek sets out with a very loud donkey by his side to ''persuade'' Farquaad to give Shrek his swamp back. Instead, a deal is made. Farquaad, who wants to become the King, sends Shrek to rescue Princess Fiona, who is awaiting her true love in a tower guarded by a fire-breathing dragon. But once they head back with Fiona, it starts to become apparent that not only does Shrek, an ugly ogre, begin to fall in love with the lovely princess, but Fiona is also hiding a huge secret.', 'https://m.media-amazon.com/images/M/MV5BN2FkMTRkNTUtYTI0NC00ZjI4LWI5MzUtMDFmOGY0NmU2OGY1XkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Shrek', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (180, 8.2, '2023-07-21', 3, 24, 23, 'tt15398776', 'A dramatization of the life story of J. Robert Oppenheimer, the physicist who had a large hand in the development of the atomic bomb, thus helping end World War 2. We see his life from university days all the way to post-WW2, where his fame saw him embroiled in political machinations.', 'https://m.media-amazon.com/images/M/MV5BN2JkMDc5MGQtZjg3YS00NmFiLWIyZmQtZTJmNTM5MjVmYTQ4XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Oppenheimer', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (73, 7.6, '2019-10-17', 28, 26, 4, 'tt12936856', 'Tae-soo is getting ready for a job in a single room that isn''t soundproof. Woo-seong recently hit the jackpot with stocks and is running a share-house. When he arrives, he sees a naked woman and mistakes her for his senior''s wife.', 'https://m.media-amazon.com/images/M/MV5BYzJkMmJjZDctOWVmYS00NTlmLTgyYWQtYmQ2NmIzYWQ4ZmU3XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Young Sister-In-Law 5', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (126, 7.9, '2008-05-02', 32, 31, 28, 'tt0371746', 'Tony Stark. Genius, billionaire, playboy, philanthropist. Son of legendary inventor and weapons contractor Howard Stark. When Tony Stark is assigned to give a weapons presentation to an Iraqi unit led by Lt. Col. James Rhodes, he''s given a ride on enemy lines. That ride ends badly when Stark''s Humvee that he''s riding in is attacked by enemy combatants. He survives - barely - with a chest full of shrapnel and a car battery attached to his heart. In order to survive he comes up with a way to miniaturize the battery and figures out that the battery can power something else. Thus Iron Man is born. He uses the primitive device to escape from the cave in Iraq. Once back home, he then begins work on perfecting the Iron Man suit. But the man who was put in charge of Stark Industries has plans of his own to take over Tony''s technology for other matters.', 'https://m.media-amazon.com/images/M/MV5BMTczNTI2ODUwOF5BMl5BanBnXkFtZTcwMTU0NTIzMw@@._V1_SX300.jpg', 'PG-13', null, 'Iron Man', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (44, 8, '2023-11-22', 33, 32, 4, 'tt27558577', 'Join Hannah Waddingham for stunning performances including Phil Dunster, Luke Evans, Leslie Odom Jr., Sam Ryder, and more.', 'https://m.media-amazon.com/images/M/MV5BNzEzZDlhOWQtMmQyMS00MTc5LTg3YTQtMTJjYzlkMDk4YWU5XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Hannah Waddingham: Home for Christmas', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (126, 5.7, '2026-03-06', 40, 39, 36, 'tt30851137', 'Dr. Frankenstein''s lonely Creature travels to 1930s Chicago to seek the aide of a Dr. Euphronius in creating a companion for him. The doctor reinvigorates a murdered young woman and the Bride is born. She is beyond what either of them intended, igniting a combustible romance, the attention of the police and a wild and radical social movement.', 'https://m.media-amazon.com/images/M/MV5BM2VmMDVlNzgtNThhZC00ZGMwLTg4MmEtZTUzNmRiYTkxYzUyXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'The Bride!', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (100, 6.9, '2022-03-11', 41, 40, 37, 'tt8097030', 'Mei Lee (voice of Rosalie Chiang) is a confident, dorky 13-year-old torn between staying her mother''s dutiful daughter and the chaos of adolescence. Her protective, if not slightly overbearing mother, Ming (voice of Sandra Oh), is never far from her daughter - an unfortunate reality for the teenager. And as if changes to her interests, relationships and body weren''t enough, whenever she gets too excited (which is practically ALWAYS), she "poofs" into a giant red panda.', 'https://m.media-amazon.com/images/M/MV5BODY2NjExYmUtZTQ4NS00NzM2LWE2NWYtZWY2NGIyOTBmNzI3XkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Turning Red', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (149, 8.4, '2018-04-27', 50, 49, 46, 'tt4154756', 'As the Avengers and their allies have continued to protect the world from threats too large for any one hero to handle, a new danger has emerged from the cosmic shadows: Thanos. A despot of intergalactic infamy, his goal is to collect all six Infinity Stones, artifacts of unimaginable power, and use them to inflict his twisted will on all of reality. Everything the Avengers have fought for has led up to this moment, the fate of Earth and existence has never been more uncertain.', 'https://m.media-amazon.com/images/M/MV5BMjMxNjY2MDU1OV5BMl5BanBnXkFtZTgwNzY1MTUwNTM@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Avengers: Infinity War', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (200, 7.3, '2026-01-23', 55, 54, 51, 'tt30387012', 'Young Indian fighters prepared to protect their homeland from a greater threat during the 1971 Indo-Pak war.', 'https://m.media-amazon.com/images/M/MV5BYjdhNmE4MTItYjZlYi00MjQ2LTliOGMtN2ViMzU0M2M3ODMyXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Border 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (136, 6.2, '2026-02-13', 59, 59, 55, 'tt32897959', 'A passionate and tumultuous love story set against the backdrop of the Yorkshire moors, exploring the intense and destructive relationship between Heathcliff and Catherine Earnshaw.', 'https://m.media-amazon.com/images/M/MV5BMGFlMTVkMDktZGMzMC00Yjk4LWFmNzEtNTFmMzM2YzM3MWFkXkEyXkFqcGc@._V1_QL75_UY562_CR35,0,380,562_.jpg', 'R', null, 'Wuthering Heights', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (194, 8, '1997-12-19', 62, 62, 58, 'tt0120338', '84 years later, a 100 year-old woman named Rose DeWitt Bukater tells the story to her granddaughter Lizzy Calvert, Brock Lovett, Lewis Bodine, Bobby Buell and Anatoly Mikailavich on the Keldysh about her life set in April 10th 1912, on a ship called Titanic when young Rose boards the departing ship with the upper-class passengers and her mother, Ruth DeWitt Bukater, and her fiancé, Caledon Hockley. Meanwhile, a drifter and artist named Jack Dawson and his best friend Fabrizio De Rossi win third-class tickets to the ship in a game. And she explains the whole story from departure until the death of Titanic on its first and last voyage April 15th, 1912 at 2:20 in the morning.', 'https://m.media-amazon.com/images/M/MV5BYzYyN2FiZmUtYWYzMy00MzViLWJkZTMtOGY1ZjgzNWMwN2YxXkEyXkFqcGc@._V1_QL75_UX380_CR0,2,380,562_.jpg', 'PG-13', null, 'Titanic', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (189, 8.6, '1999-12-10', 31, 64, 29, 'tt0120689', 'Based on Stephen King''s 1996 novel of the same name. Stars Tom Hanks as a death row corrections officer during the U.S. Great Depression who witnesses supernatural events that occur after an enigmatic inmate (Michael Clarke Duncan) is brought to his facility.', 'https://m.media-amazon.com/images/M/MV5BMTUxMzQyNjA5MF5BMl5BanBnXkFtZTYwOTU2NTY3._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'The Green Mile', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (161, 7.7, '2025-09-26', 70, 72, 66, 'tt30144839', 'Washed-up revolutionary Bob exists in a state of stoned paranoia, surviving off-grid with his spirited, self-reliant daughter, Willa. When his evil nemesis resurfaces after 16 years and she goes missing, the former radical scrambles to find her, father and daughter both battling the consequences of his past.', 'https://m.media-amazon.com/images/M/MV5BMzBkZmQ0NjMtNTZlMy00ZjdlLTg5ODUtYWFlNGM0YzE3MTg0XkEyXkFqcGc@._V1_QL75_UY562_CR35,0,380,562_.jpg', 'R', null, 'One Battle After Another', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (117, 4.9, '2011-11-18', 27, 25, 24, 'tt1324999', 'Bella and Edward celebrate their wedding, but, after their honeymoon on Isle Esme, things take a turn for the worse when Bella realises she is pregnant. As the baby grows at an abnormally fast rate and causes many health problems to Bella, Edward and the wolf pack fear that she may give birth to an immortal child. But the Cullens will do everything they can to ensure that both Bella and the unborn child remain safe.', 'https://m.media-amazon.com/images/M/MV5BNjBlY2M2MTctMzU3Yi00MTY3LTlkMTAtMzhlMzY1YjZlYTA2XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Twilight Saga: Breaking Dawn - Part 1', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (88, 5.7, '2025-12-18', 30, 29, 27, 'tt23572848', 'Desperate to be a big guy, SpongeBob sets out to prove his bravery to Mr. Krabs by following the Flying Dutchman, a mysterious swashbuckling ghost pirate, to the deepest depths of the deep sea.', 'https://m.media-amazon.com/images/M/MV5BYzdlYmM2YmEtMmQ3Zi00ZjAxLTg2ZjctNzU3NDVkY2RiOTBjXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'The SpongeBob Movie: Search for SquarePants', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (113, 6.8, '2026-01-16', 34, 33, 30, 'tt32642706', 'A Miami narcotics unit fractures from the inside after discovering a cartel stash house loaded with cash, six weeks after their captain''s unsolved murder. The city itself feels like a pressure cooker, and the team feels it: loyalty curdles fast when the numbers have that many zeroes. Carnahan keeps the interrogation frame tight, feeding information in controlled doses, trusting the ensemble to carry the weight of suspicion before the plot demands anything explicit of them. It mostly works.', 'https://m.media-amazon.com/images/M/MV5BNjIzMGY3MzMtNDVlMS00MGU1LTkyNTItMmI4Mzk0Mjg3OTBkXkEyXkFqcGc@._V1_QL75_UY562_CR35,0,380,562_.jpg', 'R', null, 'The Rip', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (115, 6.3, '2015-06-26', 39, 38, 35, 'tt2637276', 'Months after John''s divorce, Ted and Tami-Lynn''s marriage seems to be on the same road. To patch things up, Ted and Tami-Lynn plan to have a child with John''s help, but their failed efforts backfire disastrously. Namely, Ted is declared property by the government, and he loses all of his civil rights. Now, Ted must fight a seemingly hopeless legal battle with an inexperienced young lawyer to regain his rightful legal status. Unfortunately, between Ted''s drunken idiocies and sinister forces interested in this situation to exploit him, Ted''s quest has all the odds against him.', 'https://m.media-amazon.com/images/M/MV5BMjEwMDg3MDk1NF5BMl5BanBnXkFtZTgwNjYyODA1NTE@._V1_SX300.jpg', 'R', null, 'Ted 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (114, 6.8, '2023-07-21', 42, 41, 38, 'tt1517268', 'Barbie the Doll lives in bliss in the matriarchal society of Barbieland feeling good about her role in the world in the various iterations of Barbies over the years showing girls that play with her that they can be whatever and whoever they want. On the flip side, Ken, who also lives in Barbieland, is unnoticed except in relation to Barbie, which is however one step above any other doll in Barbieland, such as Allan. One day, Stereotypical Barbie begins to have feelings which she''s never experienced which leads to her world seemingly falling apart. Weird Barbie determines that there is something happening in the real world with someone playing with her being unhappy leading to Stereotypical Barbie reluctantly heading to the real world to rectify what is happening with that person, she first needing to find this person. Much to Barbie''s chagrin, the original Ken, Beach Ken, tags along with her to the real world in he needing to survive in her presence. Beyond their mission to find this person, Barbie and Ken will find the real world unlike anything they know in Barbieland, especially in it being a male dominated society. While Barbie still has to find out what''s going on that made her come to the real world, Ken is finding a newfound control which he wants to bring back to Barbieland. If he is able to do so, the role of Barbie in the real world may be forever changed. On top of everything, executives at Mattel, primarily white men, discover that a "real life" Barbie and Ken doll have infiltrated the real world, their mission to capture the pair, but especially Barbie, to put them/her back in their/her place, namely in a manufacturer''s sealed box.', 'https://m.media-amazon.com/images/M/MV5BYjI3NDU0ZGYtYjA2YS00Y2RlLTgwZDAtYTE2YTM5ZjE1M2JlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Barbie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (105, 6.5, '2026-02-20', 46, 45, 42, 'tt4357198', 'Disowned at birth by his obscenely wealthy family, a blue-collar will stop at nothing to reclaim his inheritance, no matter how many relatives stand in his way.', 'https://m.media-amazon.com/images/M/MV5BOTkwY2JjMWYtOGU4YS00ZTg0LWIzYzUtZDkxNDE5NWNkNWM1XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'How to Make a Killing', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (144, 7.9, '2025-01-29', 48, 47, 44, 'tt34956443', 'After a great catastrophe, the souls of Nezha and Aobing are saved, but their bodies face ruin. To give them new life, Taiyi Zhenren turns to the mystical seven-colored lotus in a daring bid to rebuild them and change their fate.', 'https://m.media-amazon.com/images/M/MV5BYjIyMDc3ZmQtZTQyYy00NDhhLTlmMWEtYzM3MDYwNjRmY2NkXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Ne Zha 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (201, 9, '2003-12-17', 53, 52, 49, 'tt0167260', 'The final confrontation between the forces of good and evil fighting for control of the future of Middle-earth. Frodo and Sam reach Mordor in their quest to destroy the One Ring, while Aragorn leads the forces of good against Sauron''s evil army at the stone city of Minas Tirith.', 'https://m.media-amazon.com/images/M/MV5BMTZkMjBjNWMtZGI5OC00MGU0LTk4ZTItODg2NWM3NTVmNWQ4XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Lord of the Rings: The Return of the King', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (96, 7.5, '2024-06-14', 56, 55, 52, 'tt22022452', 'A sequel that features Riley entering puberty and experiencing brand new, more complex emotions as a result. As Riley tries to adapt to her teenage years, her old emotions try to adapt to the possibility of being replaced.', 'https://m.media-amazon.com/images/M/MV5BYWY3MDE2Y2UtOTE3Zi00MGUzLTg2MTItZjE1ZWVkMGVlODRmXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Inside Out 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (155, 7.6, '2025-06-27', 61, 61, 57, 'tt16311594', 'Dubbed "the greatest that never was," Sonny Hayes was FORMULA 1''s most promising phenom of the 1990s until an accident on the track nearly ended his career. Thirty years later, he''s a nomadic racer-for-hire when he''s approached by his former teammate Ruben Cervantes, owner of a struggling FORMULA 1 team that is on the verge of collapse. Ruben convinces Sonny to come back to FORMULA 1 for one last shot at saving the team and being the best in the world. He''ll drive alongside Joshua Pearce, the team''s hotshot rookie intent on setting his own pace. But as the engines roar, Sonny''s past catches up with him and he finds that in FORMULA 1, your teammate is your fiercest competition--and the road to redemption is not something you can travel alone.', 'https://m.media-amazon.com/images/M/MV5BNGI0MDI4NjEtOWU3ZS00ODQyLWFhYTgtNGYxM2ZkM2Q2YjE3XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'F1: The Movie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (117, 8.4, '2018-12-14', 68, 69, 64, 'tt4633694', 'Phil Lord and Christopher Miller, the creative minds behind The Lego Movie and 21 Jump Street, bring their unique talents to a fresh vision of a different Spider-Man Universe, with a groundbreaking visual style that''s the first of its kind. "Spider-Man(TM): Into the Spider-Verse" introduces Brooklyn teen Miles Morales (Shameik Moore), and the limitless possibilities of the Spider-Verse, where more than one can wear the mask.', 'https://m.media-amazon.com/images/M/MV5BMjMwNDkxMTgzOF5BMl5BanBnXkFtZTgwNTkwNTQ3NjM@._V1_SX300.jpg', 'PG', null, 'Spider-Man: Into the Spider-Verse', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (155, 8.4, '2025-09-12', 35, 34, 31, 'tt32820897', 'The Demon Slayer Corps are drawn into the Infinity Castle, where Tanjiro and the Hashira face terrifying Upper Rank demons in a desperate fight as the final battle against Muzan Kibutsuji begins.', 'https://m.media-amazon.com/images/M/MV5BOGQ3YWUzYjEtMTJiYy00ZjQ0LWI0YjktYjhiNGVhNGExYTM3XkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Demon Slayer: Kimetsu no Yaiba Infinity Castle', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (133, 6.5, '2026-04-17', 43, 42, 39, 'tt32612507', 'The young daughter of a journalist disappears into the desert without a trace. Eight years later, the broken family is shocked when she is returned to them, as what should be a joyful reunion turns into a living nightmare.', 'https://m.media-amazon.com/images/M/MV5BNWQ1NzI2YTUtN2E0ZS00YzVmLTkxNjktMWIzNTYwMzkyOTU0XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Lee Cronin''s the Mummy', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (107, 6.8, '2022-07-29', 60, 60, 56, 'tt11976532', 'A writer from New York City attempts to solve the murder of a girl he hooked up with and travels down south to investigate the circumstances of her death and discover what happened to her.', 'https://m.media-amazon.com/images/M/MV5BYmI2MmZlNTctYjIyMy00N2MxLTllZWQtNmEyOGZhMGQ3NThiXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Vengeance', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (156, 8.4, '2026-03-20', 67, 68, 63, 'tt12042730', 'Middle school science teacher Ryland Grace (Ryan Gosling) wakes up on a spaceship light-years from home with no recollection of who he is or how he got there. As his memory returns, he begins to uncover his mission: to solve the riddle of the mysterious substance that is causing the sun to die out. He must call on his scientific knowledge and unorthodox ideas to save everything on Earth from extinction... but an unexpected friendship means he may not have to do it alone.', 'https://m.media-amazon.com/images/M/MV5BNTkwNzJiYTctNzI3NC00NjE1LTlhYjktY2Q5MTdmMWFmNzcxXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Project Hail Mary', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (92, 7, '2023-04-05', 72, 74, 68, 'tt6718170', 'A Brooklyn plumber named Mario travels through the Mushroom Kingdom with a princess named Peach and an anthropomorphic mushroom named Toad to find Mario''s brother, Luigi, and to save the world from a ruthless fire-breathing Koopa named Bowser.', 'https://m.media-amazon.com/images/M/MV5BOGZlN2EzOTYtMzUzOS00NTM3LTg0MTQtZDVjZGM4YmJlNWNhXkEyXkFqcGc@._V1_QL75_UY562_CR0,0,380,562_.jpg', 'PG', null, 'The Super Mario Bros. Movie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (197, 7.3, '2025-12-19', 62, 81, 75, 'tt1757678', 'Jake and Neytiri''s family grapples with grief, encountering a new, aggressive Na''vi tribe, the Ash People, who are led by the fiery Varang, as the conflict on Pandora escalates and a new moral focus emerges.', 'https://m.media-amazon.com/images/M/MV5BZDYxY2I1OGMtN2Y4MS00ZmU1LTgyNDAtODA0MzAyYjI0N2Y2XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Avatar: Fire and Ash', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (104, 7.4, '2026-03-06', 88, 91, 84, 'tt26443616', 'A 19-year-old animal lover uses technology that places her consciousness into a robotic beaver to uncover mysteries within the animal world beyond her imagination.', 'https://m.media-amazon.com/images/M/MV5BNzRiMzZlMTMtNmU3OC00MDUwLThmNDUtMTBjZmQ3MWQ4NTljXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'Hoppers', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (140, 6.8, '2026-02-13', 96, 100, 93, 'tt32430579', 'Set against the sun-bleached grit of Los Angeles, CRIME 101 weaves the tale of an elusive thief (Chris Hemsworth) whose high-stakes heists unfolding along the iconic 101 freeway have mystified police. When he eyes the score of a lifetime with hopes of this being his final job, his path collides with a disillusioned insurance broker (Halle Berry) who is facing her own crossroads, forcing the two to collaborate. Determined to crack the case, a relentless detective (Mark Ruffalo) closes in on the operation, raising the stakes even higher. As the multimillion-dollar heist approaches, the line between hunter and hunted begins to blur, and all three are forced to confront the cost of their choices - and the realization that there''s no turning back.', 'https://m.media-amazon.com/images/M/MV5BZThlN2M4ZTUtYTU3Mi00MDE5LWFhYWUtNjkxMWEwNjUwNDVhXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Crime 101', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (107, 6.1, '2026-01-30', 10, 115, 106, 'tt32357218', 'Michael Mason is a recluse on a remote Scottish island who rescues a girl from the sea, unleashing a perilous sequence of events that culminate in an attack on his home, compelling him to face his turbulent history.', 'https://m.media-amazon.com/images/M/MV5BMzI2ODY3MzQtYzllNy00YWM1LWExZTgtOGIwNjk2MmE2MmY2XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Shelter', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (91, 4.1, '2026-02-06', 112, 124, 115, 'tt28682323', 'The Strangers - Chapter 3, the franchise''s most brutal chapter yet, descends into darker territory than ever as the mythology of the Strangers unravels and the bloodshed mounts. Maya is the Final Girl trapped in the Strangers'' unceasing cycle of violence, pushed toward an inevitable face-off with the masked killers--a terrifying nightmare where the only way out is in.', 'https://m.media-amazon.com/images/M/MV5BZGQ2ZDJlMjgtYmMwNi00MjAxLWIzOWYtMzE0YTFjZWYyNmEzXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'The Strangers: Chapter 3', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (100, 6.7, '2026-02-13', 117, 132, 123, 'tt27613895', 'A young anthropomorphic goat named Will Harris dreams of playing roar-ball, a high-intensity, animalistic version of basketball dominated by much larger, fiercer creatures. After a video of Will challenging the league''s MVP, Mane Attraction, goes viral, he is recruited as a marketing tactic for the struggling Vineland Thorns.', 'https://m.media-amazon.com/images/M/MV5BYzE5OTJkOGMtYWFiNi00NTlkLWE3ZWItY2ZlNjkyOWVhMjMyXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'PG', null, 'GOAT', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (93, 5.4, '1997-12-31', 122, 139, 129, 'tt0208715', 'Jenny, a clever script assistant, lives with Geoff, recently returned to Toronto from Hollywood to direct a televised lottery show. Jenny comes up with a scheme for beating the lottery, which involves the seduction of Byron, an accountant who was hired to keep the lottery honest after the previous accountant dropped dead during the show. As the scheme proceeds, difficulties arise. A cleaning man, originally from India, is suspicious when he sees the lottery - supposedly live - being pre-taped; and the person chosen to buy the winning ticket is pursued by a loan shark. As the scheme unwinds, more and more people in Toronto - and India - learn the winning numbers of the upcoming draw. Meanwhile, Jenny and the accountant start falling in love. Her determined efforts ultimately turn an imminent disaster into a financial and romantic success.', 'https://m.media-amazon.com/images/M/MV5BMDQ1ZDA1ZGYtMmE4Zi00YTJkLWFiYzYtODMyMTkyMzQ2OWJjXkEyXkFqcGdeQXVyMjAxMjEzNzU@._V1_SX300.jpg', 'N/A', null, 'Balls Up', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (86, 5.1, '2026-04-10', 130, 147, 137, 'tt32362890', 'In the midst of a raging hurricane, a coastal community fights for survival as they are besieged not only by the destructive forces of nature but also by the relentless threat of sharks. Struggling against the pounding rain, debris-strewn streets, and enveloping darkness, they must band together to fend off these deadly predators if they have any hope of making it through the storm alive.', 'https://m.media-amazon.com/images/M/MV5BODMxNjdhMWQtMmJhYS00MDc1LTkyYzAtYTgzZTFhMmI1ODEyXkEyXkFqcGc@._V1_QL75_UY562_CR35,0,380,562_.jpg', 'R', null, 'Thrash', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (105, 7.5, '2026-04-03', 63, 63, 59, 'tt33071426', 'A happily-engaged couple is put to the test when an unexpected turn sends their wedding week off the rails.', 'https://m.media-amazon.com/images/M/MV5BMTcwOGZhYmItYTg3ZS00NjUwLWJiMmQtMjU5YjEwYWY0NmNkXkEyXkFqcGc@._V1_QL75_UX380_CR0,16,380,562_.jpg', 'R', null, 'The Drama', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (131, 6.8, '2025-12-19', 64, 67, 62, 'tt27543632', 'Millie arrives at a wealthy household seeking stability after instability. The Catalyst appears in the uneasy dynamic between Nina and Andrew, where generosity carries control beneath it. Millie responds by reading the room and using charm as survival instinct. As the Collision builds, attention, jealousy, and shifting alliances turn the home into a tense psychological arena. A Moral Pivot arrives when Millie must choose whether to remain pliant or assert herself within a system that rewards manipulation, and the cost of either path presses directly on her sense of identity.', 'https://m.media-amazon.com/images/M/MV5BZDFmYmEzYmItMmY0ZC00Y2Y0LTliNjYtY2E3YWZkZjIyNzBjXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'The Housemaid', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (7, 7.7, '2019-03-09', 69, 70, 65, 'tt9746458', 'Old friends Wyatt and Patricia are struggling to reconnect over dinner. Then Patricia''s dad shows up.', 'https://m.media-amazon.com/images/M/MV5BYmJlODRhMWUtN2YzZS00NTNhLTljZmItMGY3ODM4MjFlNTdkXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Stepdaddy', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (89, 4.9, '1997-04-11', 73, 75, 69, 'tt0118615', 'When a documentary crew traveling through the Amazon jungle, picks up a stranded man, they are unaware of the trouble that will occur. This stranger''s hobby is to capture the giant Anaconda snake, and plans to continue targeting it on their boat, by any means necessary.', 'https://m.media-amazon.com/images/M/MV5BMmU2ZGYyZDAtZGM3My00NjQ4LTlmZmQtNzY4OGRlNDFjNTE4XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Anaconda', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 6.2, '1979-01-24', 77, 79, 73, 'tt0077123', 'In the summer of 1939, 13-year-old Marie goes with her parents to visit her grandmother in a small town near Avignon. Although rumors of war reach the countryside, it''s an idyllic place, and Marie''s parents are constantly making love. Surrounded by sexual frankness, Marie fancies herself a woman and develops a crush on Alexander, the town''s young Jewish doctor, and is despondent when he treats her like a child. When her father abruptly leaves for a few weeks to help with a relative''s harvest, her mother and the doctor disappear into the woods for hours at a time. Marie tries to spy on them. When Papa returns, what will the family and the doctor do?', 'https://m.media-amazon.com/images/M/MV5BNDgxMWQ3MjMtMWI2OC00YjExLWE5YWEtYjVkY2RiZGY4OWE3XkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'The Adolescent', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (141, 7.1, '2025-08-16', 79, 82, 76, 'tt34610311', 'Macau Police brings the tracking expert police officer out of retirement to help catch a dangerous group of professional thieves.', 'https://m.media-amazon.com/images/M/MV5BN2ZhMGU1MTItMzBkMi00MjZmLWI2MDQtMWE1ODNjMWFhZjY4XkEyXkFqcGc@._V1_SX300.jpg', 'TV-MA', null, 'The Shadow''s Edge', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 5.5, '2017-03-28', 83, 86, 4, 'tt5168832', 'After Porn Ends 2 picks up where its predecessor left off, and not only turns back the clock to meet the oldest living stars in adult film''s history, but goes in depth with some of its most current retirees, and juxtaposes their experiences in a life after porn. Delving deeper into society''s ongoing stigmas of race, misogyny, and the reality of decreasing opportunities for these former VHS box cover stars. For some, their careers in adult entertainment are accepted proudly and without regret. In fact, it seems to have proven to be the pathway to their current happiness and inner peace. For others, however, a career in porn has proven to be a conduit to certain despair as they struggle to find a way to bury their past and emerge with a new career or calling.', 'https://m.media-amazon.com/images/M/MV5BNjgxNzUxMWMtMjM4MC00NjBiLTkxM2EtMWY5YzBhNDI2ZmY3XkEyXkFqcGc@._V1_SX300.jpg', 'TV-MA', null, 'After Porn Ends 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (111, 5.8, '2026-04-09', 89, 92, 85, 'tt38365045', 'A video-game designer''s will is tested when a mysterious spirit infiltrates his new family and threatens the life of his expecting wife.', 'https://m.media-amazon.com/images/M/MV5BMDAzNmE0OWUtMTc4ZS00MDkzLWI2ZmMtMzA3MGEyNjU0MDIwXkEyXkFqcGc@._V1_QL75_UY562_CR4,0,380,562_.jpg', 'N/A', null, 'Mudborn', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (175, 9.2, '1972-03-24', 78, 94, 87, 'tt0068646', 'The Godfather "Don" Vito Corleone is the head of the Corleone mafia family in New York. He is at the event of his daughter''s wedding. Michael, Vito''s youngest son and a decorated WWII Marine is also present at the wedding. Michael seems to be uninterested in being a part of the family business. Vito is a powerful man, and is kind to all those who give him respect but is ruthless against those who do not. But when a powerful and treacherous rival wants to sell drugs and needs the Don''s influence for the same, Vito refuses to do it. What follows is a clash between Vito''s fading old values and the new ways which may cause Michael to do the thing he was most reluctant in doing and wage a mob war against all the other mafia families which could tear the Corleone family apart.', 'https://m.media-amazon.com/images/M/MV5BNGEwYjgwOGQtYjg5ZS00Njc1LTk2ZGEtM2QwZWQ2NjdhZTE5XkEyXkFqcGc@._V1_QL75_UY562_CR8,0,380,562_.jpg', 'R', null, 'The Godfather', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (100, 6.3, '2024-11-27', 94, 98, 91, 'tt13622970', 'After receiving an unexpected call from her wayfinding ancestors, Moana must journey to the far seas of Oceania and into dangerous, long-lost waters for an adventure unlike anything she''s ever faced.', 'https://m.media-amazon.com/images/M/MV5BZDUxNThhYTUtYjgxNy00MGQ4LTgzOTEtZjg1YTU5NTcwNThlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'Moana 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (117, 6.6, '2005-06-29', 6, 101, 94, 'tt0407304', 'An ordinary man has to protect his children against alien invaders in this science fiction action film freely adapted from the classic story by H.G. Wells. Ray Ferrier (Tom Cruise) is a dockworker living in New Jersey, divorced from his first wife Mary Ann (Miranda Otto) and estranged from his two children Rachel and Robbie (Dakota Fanning and Justin Chatwin), of whom he has custody on weekends. On one such visitation, looking after the kids becomes a little more difficult when, after a series of strange lighting storms hit his neighborhood, Ray discovers that a fleet of death-ray robotic spaceships have emerged nearby, part of the first wave of an all-out alien invasion of the Earth. Transporting his children from New York to Boston in an attempt to find safety at Mary Ann''s parents'' house, Ray must learn to become the protector and provider he never was in marriage.', 'https://m.media-amazon.com/images/M/MV5BNDUyODAzNDI1Nl5BMl5BanBnXkFtZTcwMDA2NDAzMw@@._V1_SX300.jpg', 'PG-13', null, 'War of the Worlds', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (154, 8.8, '1994-10-14', 106, 118, 109, 'tt0110912', 'Jules Winnfield (Samuel L. Jackson) and Vincent Vega (John Travolta) are two hit men who are out to retrieve a suitcase stolen from their employer, mob boss Marsellus Wallace (Ving Rhames). Wallace has also asked Vincent to take his wife Mia (Uma Thurman) out a few days later when Wallace himself will be out of town. Butch Coolidge (Bruce Willis) is an aging boxer who is paid by Wallace to lose his fight. The lives of these seemingly unrelated people are woven together comprising of a series of funny, bizarre and uncalled-for incidents.', 'https://m.media-amazon.com/images/M/MV5BYTViYTE3ZGQtNDBlMC00ZTAyLTkyODMtZGRiZDg0MjA2YThkXkEyXkFqcGc@._V1_QL75_UY562_CR3,0,380,562_.jpg', 'R', null, 'Pulp Fiction', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (162, 7.9, '2009-12-18', 62, 71, 58, 'tt0499549', 'When his brother is killed in a robbery, paraplegic Marine Jake Sully decides to take his place in a mission on the distant world of Pandora. There he learns of greedy corporate figurehead Parker Selfridge''s intentions of driving off the native humanoid "Na''vi" in order to mine for the precious material scattered throughout their rich woodland. In exchange for the spinal surgery that will fix his legs, Jake gathers knowledge, of the Indigenous Race and their Culture, for the cooperating military unit spearheaded by gung-ho Colonel Quaritch, while simultaneously attempting to infiltrate the Na''vi people with the use of an "avatar" identity. While Jake begins to bond with the native tribe and quickly falls in love with the beautiful alien Neytiri, the restless Colonel moves forward with his ruthless extermination tactics, forcing the soldier to take a stand - and fight back in an epic battle for the fate of Pandora.', 'https://m.media-amazon.com/images/M/MV5BMDEzMmQwZjctZWU2My00MWNlLWE0NjItMDJlYTRlNGJiZjcyXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Avatar', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 8, '2016-03-04', 71, 73, 67, 'tt2948356', 'From the largest elephant to the smallest shrew, the city of Zootopia is a mammal metropolis where various animals live and thrive. When Judy Hopps becomes the first rabbit to join the police force, she quickly learns how tough it is to enforce the law. Determined to prove herself, Judy jumps at the opportunity to solve a mysterious case. Unfortunately, that means working with Nick Wilde, a wily fox who makes her job even harder.', 'https://m.media-amazon.com/images/M/MV5BOTMyMjEyNzIzMV5BMl5BanBnXkFtZTgwNzIyNjU0NzE@._V1_SX300.jpg', 'PG', null, 'Zootopia', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (86, 6.5, '1951-11-16', 74, 77, 71, 'tt0044166', 'Prominent attorney Brad Mason takes on the defense of Rudi Walchek, a young hit-man hoodlum accused of murder. Convinced of the youthful thug''s innocence, Mason get him acquitted. Later, he learns from the murder-victim''s father that Walchek is a low-level member of a protection-racket gang and was undoubtedly guilty. Mason is anxious to get the gang-leader, but when he discovers it is the eminently respected head of the city''s Crime Commission, he feels that a conviction in a court-of-law would be impossible. In a rage, he kills the man, but all evidence, including the murder weapon points to Walchek. When the latter is again brought to trial, Mason, although he senses a higher justice is at work, feels he must defend him with the best of his ability.', 'https://m.media-amazon.com/images/M/MV5BOTE4M2JhM2YtNTlmMy00YWJjLThjM2MtODE0NGRmMTA5ZjBkXkEyXkFqcGc@._V1_SX300.jpg', 'Approved', null, 'The Unknown Man', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (128, 7.4, '1992-11-13', 78, 80, 74, 'tt0103874', 'This version of Dracula is closely based on Bram Stoker''s classic novel. Young barrister Jonathan Harker is assigned to a gloomy village in the mists of eastern Europe. He is captured and imprisoned by the undead vampire Dracula, who travels to London, inspired by a photograph of Harker''s betrothed, Mina Murray. In Britain, Dracula begins a reign of seduction and terror, draining the life from Mina''s closest friend, Lucy Westenra. Lucy''s friends gather together to try to drive Dracula away.', 'https://m.media-amazon.com/images/M/MV5BMmVhNzhlMzMtYjJkNy00ODU4LWJmMjUtYzdlMGI3MTQ3YzBhXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Dracula', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (94, 6.2, '2024-07-03', 82, 85, 79, 'tt7510222', 'Gru, Lucy, Margo, Edith, and Agnes welcome a new member to the family, Gru Jr., who is intent on tormenting his dad. Gru faces a new nemesis in Maxime Le Mal and his girlfriend Valentina, and the family is forced to go on the run.', 'https://m.media-amazon.com/images/M/MV5BNzY0ZTlhYzgtOTgzZC00ZTg2LTk4NTEtZDllM2E2NGE5Njg2XkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Despicable Me 4', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (98, 4.8, '2021-10-22', 85, 88, 81, 'tt13069986', 'Just as Tessa makes the biggest decision of her life, everything changes. Revelations about her family, and then Hardin''s, throw everything they knew before in doubt and makes their hard-won future together more difficult to claim.', 'https://m.media-amazon.com/images/M/MV5BMmM0MTZhOGItZDQ3OC00MDhjLThiZjEtMWJkNjUxNzk1MGJhXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'After We Fell', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (143, 8, '2012-05-04', 87, 90, 83, 'tt0848228', 'Loki, the adopted brother of Thor, teams-up with the Chitauri Army and uses the Tesseract''s power to travel from Asgard to Midgard to plot the invasion of Earth and become a king. The director of the agency S.H.I.E.L.D., Nick Fury, sets in motion project Avengers, joining Tony Stark a.k.a. the Iron Man; Steve Rogers, a.k.a. Captain America; Bruce Banner, a.k.a. The Hulk; Thor; Natasha Romanoff, a.k.a. Black Widow; and Clint Barton, a.k.a. Hawkeye, to save the world from the powerful Loki and the alien invasion.', 'https://m.media-amazon.com/images/M/MV5BNGE0YTVjNzUtNzJjOS00NGNlLTgxMzctZTY4YTE1Y2Y1ZTU4XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'The Avengers', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (106, 8.4, '2017-04-07', 92, 97, 90, 'tt5311514', 'Mitsuha is the daughter of the mayor of a small mountain town. She''s a straightforward high school girl who lives with her sister and her grandmother and has no qualms about letting it be known that she''s uninterested in Shinto rituals or helping her father''s electoral campaign. Instead she dreams of leaving the boring town and trying her luck in Tokyo. Taki is a high school boy in Tokyo who works part-time in an Italian restaurant and aspires to become an architect or an artist. Every night he has a strange dream where he becomes...a high school girl in a small mountain town.', 'https://m.media-amazon.com/images/M/MV5BMjI1ODZkYTgtYTY3Yy00ZTJkLWFkOTgtZDUyYWM4MzQwNjk0XkEyXkFqcGc@._V1_SX300.jpg', 'TV-PG', null, 'Your Name.', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (124, 6.4, '2026-01-28', 95, 99, 92, 'tt33046197', 'Estranged half brothers Jonny, a volatile suspended cop, and James, a disciplined Navy SEAL, who reunite after the mysterious death of their father, private investigator Walter Hale. Initially indifferent and long out of contact, the brothers are forced together when Yakuza operatives begin hunting for a package Walter supposedly sent, pushing them into a dangerous investigation that leads them from Oklahoma to Hawaii. As they dig deeper, they uncover buried family secrets, criminal conspiracies, and the truth behind Walter''s murder, all while struggling to rebuild the fractured bond between them.', 'https://m.media-amazon.com/images/M/MV5BZDcyMmYxZmMtMjg5MC00NWMzLTgyNDEtOGI2MWEzMmFmNmVmXkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'The Wrecking Crew', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 5.8, '2023-02-03', 101, 106, 99, 'tt21308736', 'The falling in love of two people who ran away from marriage and the interesting events that followed. Istanbul, urban renewal, love and dreams come together in this movie.', 'https://m.media-amazon.com/images/M/MV5BMTY2NjBlM2MtNGNiMy00MDRjLTljNDctNGQwZDNkNDFlM2NlXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'In Your Dreams', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (83, 4.6, '2026-04-10', 102, 108, 101, 'tt23724682', 'Follows Hollywood star Reef as he is forced to confront his problems and atone for his past after being threatened by a bizarre video footage from his past.', 'https://m.media-amazon.com/images/M/MV5BMzFmMWExMmMtZmYwZi00ZDIyLTlhYTUtZmM3ZTBlZWNjOWY4XkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'Outcome', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (98, 6.4, '2026-04-01', 72, 155, 68, 'tt28650488', 'Mario ventures into space, exploring cosmic worlds and tackling galactic challenges far from the familiar Mushroom Kingdom.', 'https://m.media-amazon.com/images/M/MV5BMDg5MjRkNWEtYmU1Mi00MTExLTk5MDQtY2RiMWVkZWNiOThjXkEyXkFqcGc@._V1_QL75_UX380_CR0,20,380,562_.jpg', 'PG', null, 'The Super Mario Galaxy Movie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (142, 8.8, '1994-07-06', 84, 87, 80, 'tt0109830', 'Forrest Gump is a simple man with a low I.Q. but good intentions. He is running through childhood with his best and only friend Jenny. His ''mama'' teaches him the ways of life and leaves him to choose his destiny. Forrest joins the army for service in Vietnam, finding new friends called Dan and Bubba, he wins medals, creates a famous shrimp fishing fleet, inspires people to jog, starts a ping-pong craze, creates the smiley, writes bumper stickers and songs, donates to people and meets the president several times. However, this is all irrelevant to Forrest who can only think of his childhood sweetheart Jenny Curran, who has messed up her life. Although in the end all he wants to prove is that anyone can love anyone.', 'https://m.media-amazon.com/images/M/MV5BNDYwNzVjMTItZmU5YS00YjQ5LTljYjgtMjY2NDVmYWMyNWFmXkEyXkFqcGc@._V1_QL75_UY562_CR4,0,380,562_.jpg', 'PG-13', null, 'Forrest Gump', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (87, 5.2, '2017-02-11', 86, 89, 82, 'tt6237208', 'When a change of circumstances leaves Miriam unable to pay her college tuition, she makes a surprising decision: to start performing in adult films, using the pseudonym Belle Knox. Miriam lies to her family and her friends at school, keeping her double life a secret. But soon rumours spread and Miriam becomes the subject of vicious online attacks and unwanted attention. Miriam fights back: she talks to the media, saying her new line of work empowers her as a feminist. But her confident stand has unintended consequences. Miriam is shunned by her conservative family and her colleagues in the adult film world. One impulsive decision has quickly spiralled out of control - and Miriam''s problems are being held against her', 'https://m.media-amazon.com/images/M/MV5BNTU1ZDczZGQtN2Y0OS00ZWYxLWFlMzItNzdhZjRkYjBhYzY2XkEyXkFqcGc@._V1_SX300.jpg', 'TV-14', null, 'From Straight A''s to XXX', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (110, 6, '2024-10-25', 91, 95, 88, 'tt16366836', 'Eddie Brock and Venom must make a devastating decision as they''re pursued by a mysterious military man and alien monsters from Venom''s home world.', 'https://m.media-amazon.com/images/M/MV5BZDMyYWU4NzItZDY0MC00ODE2LTkyYTMtMzNkNDdmYmFhZDg0XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Venom: The Last Dance', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (90, 4.3, '2002-09-16', 93, 96, 89, 'tt0199007', 'An attractive woman detective, expert in cases of conjugal infidelity is hired by a mysterious millionaire, unaware that she will get involved in a feverish love triangle to gather all the evidence she needs to finish the case.', 'https://m.media-amazon.com/images/M/MV5BZTM1N2Q0YzgtMzZjNS00NWEzLTliMTItM2VmYWMzODFhMDYxXkEyXkFqcGdeQXVyMzY0MTE3NzU@._V1_SX300.jpg', 'R', null, 'Secret Pleasures', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (160, 7.4, '2024-11-22', 100, 105, 98, 'tt1262426', 'A vivid reimagining of the classic The Wizard of Oz, Wicked spotlights the untold stories of Oz''s most famous (or infamous) characters, namely the Wicked Witch of the West and her unlikely friend, Glinda the Good Witch. The show follows green-skinned star Elphaba from birth to college and through the life-changing events which eventually label her "wicked," introducing spoiled rich girl Glinda, local prince and heartthrob Fiyero and even the Wizard of Oz himself, a troubled man very unlike the one you may remember. As Elphaba, a passionate political activist if there ever was one, fights injustice and seeks to undo the mistakes of the past, dark secrets and personal tragedies shape the history of Oz, paying homage to the classic Wizard of Oz story while simultaneously changing fans'' understanding of it forever. A cautionary tale about love, friendship and trust, Wicked effortlessly reveals that there are indeed two sides to every story.', 'https://m.media-amazon.com/images/M/MV5BOWMwYjYzYmMtMWQ2Ni00NWUwLTg2MzAtYzkzMDBiZDIwOTMwXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Wicked', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (23, 5.8, '2022-05-07', 103, 111, 102, 'tt18764810', 'The Adventures of YouTuber Jamie Powell''s alter-ego, Crazy Jay.', 'https://m.media-amazon.com/images/M/MV5BYmU1MDc2ZjgtNDM3NS00ODc5LWEzYjUtMGYxMDI4MDE2MGEwXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Toaster', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (101, 6.6, '1987-11-13', 104, 112, 103, 'tt0093894', 'In the year 2019, the world economy has collapsed. The great freedoms of the United States are no longer, as the once great nation has sealed off its borders and become a militarized police state, censoring all film, art, literature, and communications. Even so, a small resistance force led by two revolutionaries manages to fight the oppression. With full control over the media, the government attempts to quell the nation''s yearning for freedom by broadcasting a number of game shows on which convicted criminals fight for their lives. The most popular and sadistic of these programs is "The Running Man," hosted by Damon Killian. When a peaceful protest of starving citizens gathers in Bakersfield, California, a police officer named Ben Richards is ordered to fire on the crowd, which he refuses to do. Subdued by the other officers, the attack is carried out, and Richards is framed for the murder of almost a hundred unarmed civilians. Following a daring jail break months later, Richards is captured once again and forced to appear on "The Running Man" with three other convicts. With their help, he fights his way through a cadre of sadistic gladiators hunting them down through the ruins of a Los Angeles earthquake, but promising Killian that he''ll return to settle the score when the show''s host double-crosses him. In the meantime, the contestants must search through the ruins for the resistance in the hopes of finally broadcasting the truth about the government.', 'https://m.media-amazon.com/images/M/MV5BMDQwYzMwMDItYzFhZC00YjkzLTlmODAtMzg3NDFlNDhhZjYzXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'The Running Man', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (133, 7.4, '2017-07-07', 105, 121, 112, 'tt2250912', 'A young Peter Parker/Spider-Man begins to navigate his newfound identity as web-slinging superhero Spider-Man. Thrilled by his experience with the Avengers, Peter returns home, where he lives with his Aunt May, under the watchful eye of his new mentor Tony Stark. Peter tries to fall back into his normal daily routine--distracted by thoughts of proving himself to be more than just your friendly neighborhood Spider-Man--but when the Vulture emerges as a new villain, everything that Peter holds most important will be threatened.', 'https://m.media-amazon.com/images/M/MV5BODY2MTAzOTQ4M15BMl5BanBnXkFtZTgwNzg5MTE0MjI@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Spider-Man: Homecoming', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (130, 8.2, '2022-05-27', 61, 130, 121, 'tt1745960', 'Set 30 years after its predecessor, it follows Maverick''s return to the United States Navy Strike Fighter Tactics Instructor program (also known as U.S. Navy-Fighter Weapons School - "TOPGUN"), where he must confront his past as he trains a group of younger pilots, among them the son of Maverick''s deceased best friend Lieutenant Nick "Goose" Bradshaw, USN.', 'https://m.media-amazon.com/images/M/MV5BMDBkZDNjMWEtOTdmMi00NmExLTg5MmMtNTFlYTJlNWY5YTdmXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Top Gun: Maverick', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (109, 6.9, '2025-12-19', 118, 134, 125, 'tt15678738', 'From the songs of his mother''s heart to the whispers of a faithful God, David''s story begins in quiet devotion. When the giant Goliath rises to terrorize a nation, a young shepherd armed with only a sling, a few stones, and unshakable faith steps forward. Pursued by power and driven by purpose, his journey tests the limits of loyalty, love, and courage--culminating in a battle not just for a crown, but for the soul of a kingdom.', 'https://m.media-amazon.com/images/M/MV5BODczZDkzMDgtYzRjMi00YWNkLWJhNzMtNGNiMzQxNzE1ZDc3XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'David', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (133, 5.8, '2025-07-02', 99, 104, 97, 'tt31036941', 'Five years after the events of Jurassic World Dominion, the planet''s ecology has proven largely inhospitable to dinosaurs. Those remaining exist in isolated equatorial environments with climates resembling the one in which they once thrived. The three most colossal creatures across land, sea and air within that tropical biosphere hold, in their DNA, the key to a drug that will bring miraculous life-saving benefits to humankind. Covert operations expert Zora Bennett is contracted to lead a skilled team on a top-secret mission to secure the genetic material. When Zora''s operation intersects with a civilian family whose boating expedition was capsized by marauding aquatic dinos, they all find themselves stranded on a forbidden island that had once housed an undisclosed research facility for Jurassic Park. There, in a terrain populated by dinosaurs of vastly different species, they come face-to-face with a sinister, shocking discovery that has been hidden from the world for decades.', 'https://m.media-amazon.com/images/M/MV5BNjg2NTcwYWQtYzk4NS00MTJhLWEzZjItMzIxNjk3YzlkYzU0XkEyXkFqcGc@._V1_QL75_UY562_CR0,0,380,562_.jpg', 'PG-13', null, 'Jurassic World: Rebirth', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (124, 7.1, '1999-05-07', 75, 107, 100, 'tt0120616', 'An English librarian called Evelyn Carnahan becomes interested in starting an archaeological dig at the ancient city of Hamunaptra. She gains the help of Rick O''Connell, after saving him from his death. What Evelyn, her brother Jonathan and Rick are unaware of is that another group of explorers are interested in the same dig. Unfortunately for everyone, this group ends up unleashing a curse which been laid on the dead High Priest Imhotep. Now ''The Mummy'' is awake and it''s going to take a lot more than guns to send him back to where he came from.', 'https://m.media-amazon.com/images/M/MV5BMTY4YWE0OGMtNjU0Yi00YzIwLTk3NTktM2ZiYWQwNjM4MmMxXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'The Mummy', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (181, 8.4, '2019-04-26', 50, 110, 46, 'tt4154796', 'After the devastating events of Avengers: Infinity War (2018), the universe is in ruins due to the efforts of the Mad Titan, Thanos. With the help of remaining allies, the Avengers must assemble once more in order to undo Thanos''s actions and undo the chaos to the universe, no matter what consequences may be in store, and no matter who they face...', 'https://m.media-amazon.com/images/M/MV5BMTc5MDE2ODcwNV5BMl5BanBnXkFtZTgwMzI2NzQ2NzM@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Avengers: Endgame', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (124, 6.9, '2010-05-07', 32, 113, 104, 'tt1228705', 'With the world now aware of his dual life as the armored superhero Iron Man, billionaire inventor Tony Stark faces pressure from the government, the press, and the public to share his technology with the military. Unwilling to let go of his invention, Stark, along with Pepper Potts, and James "Rhodey" Rhodes at his side, must forge new alliances - and confront powerful enemies.', 'https://m.media-amazon.com/images/M/MV5BYWYyOGQzOGYtMGQ1My00ZWYxLTgzZjktZWYzN2IwYjkxYzM0XkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Iron Man 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (105, 5.7, '1996-12-25', 107, 117, 108, 'tt0117038', 'Frank Quinlan and Huey Driscoll, two reporters from a Chicago-based tabloid, along with Dorothy Winters, an ''angel expert'', are asked to travel to rural Iowa to investigate a claim from an old woman that she shares her house with a real, live archangel named Michael. Upon arrival, they see that her claims are true - but Michael is not what they expected: he smokes, drinks beer, has a very active libido and has a rather colourful vocabulary. In fact, they would never believe it were it not for the two feathery wings protruding from his back. Michael agrees to travel to Chicago with the threesome, but what they don''t realise is that the journey they are about to undertake will change their lives forever.', 'https://m.media-amazon.com/images/M/MV5BYjVkZGQ0MzgtNmQyNS00MzI3LWEzZjItNDdhMDk1NjQ3ZDcyXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Michael', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (134, 5.2, '2025-04-17', 109, 120, 111, 'tt28364592', 'When a Russian submarine vanishes in the Greenland Sea, Commander Viktor Voronin leads a rescue mission to find his brother. Meanwhile, a Kraken monster emerges after a polar station''s destruction.', 'https://m.media-amazon.com/images/M/MV5BMzczMWNlZGQtMzI4OC00YmI4LWFmZTUtNGM3NDEwNDM3Yjg5XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Kraken', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (124, 8.6, '2003-03-28', 111, 122, 113, 'tt0245429', 'The fanciful adventures of a ten-year-old girl named Chihiro, who discovers a secret world when she and her family get lost and venture through a hillside tunnel. When her parents undergo a mysterious transformation, Chihiro must fend for herself as she encounters strange spirits, assorted creatures and a grumpy sorceress who seeks to prevent her from returning to the human world.', 'https://m.media-amazon.com/images/M/MV5BNTEyNmEwOWUtYzkyOC00ZTQ4LTllZmUtMjk0Y2YwOGUzYjRiXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'Spirited Away', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (106, 6.3, '2026-03-06', 114, 127, 118, 'tt15940132', 'The humid tension of a grueling Ranger selection process dissolves into pure survival horror. Recruit 81 carries the crushing weight of a dead brother into the Georgia wilderness, pushing his physical limits until the sky literally breaks open. This is not a standard training exercise. A towering, mechanical nightmare from another world descends upon the exhausted candidates, turning a test of endurance into a frantic, low-visibility hunt where the military hierarchy shatters against superior, alien technology.', 'https://m.media-amazon.com/images/M/MV5BMmM1ZTc5ZTYtOTM2My00MjBmLWE5NzktYzkyYzdlYWE3ZDAzXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'War Machine', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (87, 6.5, '2025-12-05', 116, 129, 120, 'tt38121182', 'A veil abruptly descends over the busy Shibuya area amid the bustling Halloween crowds, trapping countless civilians inside. In the aftermath, ten colonies across Japan are transformed into dens of curses.', 'https://m.media-amazon.com/images/M/MV5BODMxOWIxYzAtNTNiYi00MTk5LWE2MjUtNjM1MTg3YmQ5NTlhXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Jujutsu Kaisen: Execution', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (95, 6.9, '2019-08-21', 121, 138, 128, 'tt7798634', 'All of us have made certain efforts so our in-laws will like us, but Grace is going to have to give it her all if she wants to fit in with her brand new husband''s wealthy dynasty, who require her to follow a brutal tradition: for the bride to try to survive her wedding night while the rest of them hunt her down. The class struggle stuff hits the proverbial fan in this extremely black satire starring a brilliant Samara Weaving and including an uncommonly perverse Andie MacDowell.', 'https://m.media-amazon.com/images/M/MV5BMTViMDA4YjgtZDQ4NC00ZDk2LTg0MWItOTc4MTkwMmVkZWRmXkEyXkFqcGc@._V1_QL75_UX380_CR0,2,380,562_.jpg', 'R', null, 'Ready or Not', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (107, 5.7, '2026-04-17', 124, 141, 131, 'tt37540875', 'When a hopeful, naive college freshman, Devon, asks the cool and confident Celeste to be her roommate, a blossoming friendship spirals into a war of passive aggression.', 'https://m.media-amazon.com/images/M/MV5BYjk2YmRhNTItOGY5Ni00MjgwLTk4ZGMtMzE0MTQzMmMxYWRlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Roommates', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (95, 7.4, '2025-06-20', 127, 144, 134, 'tt14205554', 'A world-renowned K-Pop girl group balances their lives in the spotlight with their secret identities as bad-ass demon hunters, set against a colorful backdrop of fashion, food, style, and the most popular music movement of the current generation.', 'https://m.media-amazon.com/images/M/MV5BNTBiYWJlMjQtOTIyMy00NTY4LWFhOWItOWZhNzc3NGMyMjc2XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'KPop Demon Hunters', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (121, 7.4, '2002-05-03', 19, 114, 105, 'tt0145487', 'Based on Marvel Comics'' superhero character, this is a story of Peter Parker who is a nerdy high-schooler. He was orphaned as a child, bullied by jocks, and can''t confess his crush for his stunning neighborhood girl Mary Jane Watson. To say his life is "miserable" is an understatement. But one day while on an excursion to a laboratory a runaway radioactive spider bites him... and his life changes in a way no one could have imagined. Peter acquires a muscle-bound physique, clear vision, ability to cling to surfaces and crawl over walls, shooting webs from his wrist ... but the fun isn''t going to last. An eccentric millionaire Norman Osborn administers a performance enhancing drug on himself and his maniacal alter ego Green Goblin emerges. Now Peter Parker has to become Spider-Man and take Green Goblin to the task... or else Goblin will kill him. They come face to face and the war begins in which only one of them will survive at the end.', 'https://m.media-amazon.com/images/M/MV5BZWM0OWVmNTEtNWVkOS00MzgyLTkyMzgtMmE2ZTZiNjY4MmFiXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Spider-Man', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (148, 8.1, '2021-12-17', 105, 116, 107, 'tt10872600', 'Peter Parker''s secret identity is revealed to the entire world. Desperate for help, Peter turns to Doctor Strange to make the world forget that he is Spider-Man. The spell goes horribly wrong and shatters the multiverse, bringing in monstrous villains that could destroy the world.', 'https://m.media-amazon.com/images/M/MV5BMmFiZGZjMmEtMTA0Ni00MzA2LTljMTYtZGI2MGJmZWYzZTQ2XkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'PG-13', null, 'Spider-Man: No Way Home', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (102, 8.2, '2024-09-27', 110, 123, 114, 'tt29623480', 'After a shipwreck, an intelligent robot called Roz is stranded on an uninhabited island. To survive the harsh environment, Roz bonds with the island''s animals and cares for an orphaned baby goose.', 'https://m.media-amazon.com/images/M/MV5BZWNiZjVlZTUtNGUwYi00MjJmLTg2MDctNWEzYTJiMzY1ODc4XkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'The Wild Robot', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (124, 5.9, '2002-08-09', 113, 126, 117, 'tt0295701', 'Xander "XXX" Cage is a thrill seeker who until now has been deemed untouchable by the law. NSA Agent Gibbons forces XXX to cooperate with the government to infiltrate an underground Russian crime ring, and avoid going to prison. Gibbons sends XXX to enter this world of crime undetected where others have failed, using his natural athletic prowess and a whole lot of attitude. Xander must combat an organization led by a clever, ruthless and nihilistic Yorgi whose first target is the city of Prague.', 'https://m.media-amazon.com/images/M/MV5BNjY0MTc4ZDEtY2MxYi00ODIxLWJlNzQtZTlmZDVkYTYwM2NhXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'xXx', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (148, 8.8, '2010-07-16', 3, 131, 122, 'tt1375666', 'Dom Cobb is a skilled thief, the absolute best in the dangerous art of extraction, stealing valuable secrets from deep within the subconscious during the dream state, when the mind is at its most vulnerable. Cobb''s rare ability has made him a coveted player in this treacherous new world of corporate espionage, but it has also made him an international fugitive and cost him everything he has ever loved. Now Cobb is being offered a chance at redemption. One last job could give him his life back but only if he can accomplish the impossible, inception. Instead of the perfect heist, Cobb and his team of specialists have to pull off the reverse: their task is not to steal an idea, but to plant one. If they succeed, it could be the perfect crime. But no amount of careful planning or expertise can prepare the team for the dangerous enemy that seems to predict their every move. An enemy that only Cobb could have seen coming.', 'https://m.media-amazon.com/images/M/MV5BMjAxMzY3NjcxNF5BMl5BanBnXkFtZTcwNTI5OTM0Mw@@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Inception', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (202, 9, '1974-12-18', 78, 133, 124, 'tt0071562', 'The continuing saga of the Corleone crime family tells the story of a young Vito Corleone growing up in Sicily and in 1910s New York; and follows Michael Corleone in the 1950s as he attempts to expand the family business into Las Vegas, Hollywood and Cuba.', 'https://m.media-amazon.com/images/M/MV5BMDIxMzBlZDktZjMxNy00ZGI4LTgxNDEtYWRlNzRjMjJmOGQ1XkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'The Godfather Part II', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (91, 4.7, '2026-02-20', 119, 136, 126, 'tt1764551', 'A police officer tracks a killer after her husband, a highway patrolman, becomes one of his victims.', 'https://m.media-amazon.com/images/M/MV5BNmM1MWQzYmUtNjhiOS00N2RlLWJjMDUtNGM1YTQ1ZWZlZmRkXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Psycho Killer', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (114, 6.3, '2026-03-13', 125, 142, 132, 'tt33714084', 'After prison, a woman attempts to reconnect with her young daughter but faces resistance from everyone except a bar owner with ties to her child. As they grow closer, she must confront her past mistakes to build a hopeful future.', 'https://m.media-amazon.com/images/M/MV5BNjI4OGM1NDEtYzA1NS00ZDg3LWFmZjUtMjg1MGQ4MTk3NjQzXkEyXkFqcGc@._V1_QL75_UX380_CR0,20,380,562_.jpg', 'PG-13', null, 'Reminders of Him', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (89, 5.3, '1980-03-20', 131, 149, 139, 'tt0080075', 'An escaped convict plays the occupants of a remote home against one another for his own sadistic pleasure while searching for the loot he buried there following a previous robbery.', 'https://m.media-amazon.com/images/M/MV5BMjkwMDI1MjgtOWVlOS00Zjc3LWEwYzctMDdkMWUwNzMyNzI5XkEyXkFqcGc@._V1_SX300.jpg', 'Not Rated', null, 'Madness', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (88, 4.7, '1984-05-04', 133, 151, 141, 'tt0089790', 'Sixteen-year-old Albert''s mother left for a business trip abroad, and for the last week of his holiday he is alone in his beautiful villa in England with his family''s waiter Angus. But the new housekeeper Lola is coming and she immediately settles into the guest room and moves around the house in shapely dresses, and the boy is naturally fascinated by this exuberant young woman. She tries to seduce him and clashes from the beginning with Angus who warns him of the insidious character. At a time when Lola suddenly senses an illness, Albert helps her by giving her a calming agent that is suitable for heart disease.', 'https://m.media-amazon.com/images/M/MV5BNjc1NDIzYjEtMzExYy00NTAyLWI2NTQtYWJkOWViNGUwMzk3XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Lola''s Secret', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (3, 7.1, '2008-09-16', 116, 158, 4, 'tt3486354', 'Two kids fight with light sabers around the house.', 'https://m.media-amazon.com/images/M/MV5BOWFmNmMwZmYtZjA2Mi00ZWEwLTkyZTktMjQ0MWI0MWRhM2ExXkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Star Wars: The Last Jedi', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (109, 7.3, '2026-01-16', 141, 161, 149, 'tt32141377', 'In a continuation of the epic story, Dr. Kelson makes a discovery that could change the world as they know it - and Spike''s encounter with Jimmy Crystal becomes a nightmare he can''t escape. In the world of The Bone Temple, the infected are no longer the only threat to survival - the inhumanity of the survivors can be stranger and more terrifying.', 'https://m.media-amazon.com/images/M/MV5BZGU2M2Y1YTItMWYxNS00NDYxLThhOTYtNjNhOWUzNjA3MTYwXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, '28 Years Later: The Bone Temple', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (127, 7.3, '2004-02-25', 97, 125, 116, 'tt0335345', 'A depiction of the last twelve hours in the life of Jesus of Nazareth, on the day of his crucifixion in Jerusalem. The story opens in the Garden of Olives where Jesus has gone to pray after the Last Supper. Betrayed by Judas Iscariot, the controversial Jesus - who has performed ''miracles'' and has publicly announced that he is ''the Son of God'' - is arrested and taken back within the city walls of Jerusalem. There, the leaders of the Pharisees confront him with accusations of blasphemy; subsequently, his trial results with the leaders condemning him to his death. Jesus is brought before Pontius Pilate, the prefect of the Roman province of Judaea, for his sentencing. Pilate listens to the accusations leveled at Jesus by the Pharisees. Realizing that his own decision will cause him to become embroiled in a political conflict, Pilate defers to King Herod in deciding the matter of how to persecute Jesus. However, Herod returns Jesus to Pilate who, in turn, gives the crowd a choice between which prisoner they would rather to see set free - Jesus, or Barabbas. The crowd chooses to have Barabbas set free. Thus, Jesus is handed over to the Roman soldiers and is brutally flagellated. Bloody and unrecognizable, he is brought back before Pilate who, once again, presents him to the thirsty crowd - assuming they will see that Jesus has been punished enough. The crowd, however, is not satisfied. Thus, Pilate washes his hands of the entire dilemma, ordering his men to do as the crowd wishes. Whipped and weakened, Jesus is presented with the cross and is ordered to carry it through the streets of Jerusalem, all the way up to Golgotha. There, more corporal cruelty takes place as Jesus is nailed to the cross-suffering, he hangs there, left to die. Initially, in his dazed suffering, Jesus is alarmed that he has been abandoned by God his father. He then beseeches God. At the moment of his death, nature itself over-turns.', 'https://m.media-amazon.com/images/M/MV5BNzMxY2Y4MzktMGNkNC00ODFjLWI3MGMtMzM2M2ExNmQxMGFmXkEyXkFqcGc@._V1_QL75_UX380_CR0,3,380,562_.jpg', 'R', null, 'The Passion of the Christ', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (192, 7.5, '2022-12-16', 62, 135, 75, 'tt1630029', 'Jake Sully lives with his newfound family formed on the extrasolar moon Pandora. Once a familiar threat returns to finish what was previously started, Jake must work with Neytiri and the army of the Na''vi race to protect their home.', 'https://m.media-amazon.com/images/M/MV5BNWI0Y2NkOWEtMmM2OC00MjQ3LWI1YzItZGQxYzQ3NzI4NWZmXkEyXkFqcGc@._V1_SX300.jpg', 'PG-13', null, 'Avatar: The Way of Water', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (135, 6.2, '2025-09-05', 132, 150, 140, 'tt22898462', 'Inspired by the harrowing true story of the Smurl family haunting, The Conjuring: Last Rites marks the final appearance of Patrick Wilson and Vera Farmiga as Ed and Lorraine Warren. The Warrens take on their most terrifying case when a quiet Pennsylvania home becomes ground zero for a relentless supernatural siege. Get ready for a haunting rooted in real horror... and not everyone will make it out unscathed.', 'https://m.media-amazon.com/images/M/MV5BM2VmMzRkYzgtMzg2ZC00OTFkLTkwMTYtNTMxNjM2YzI1MjgyXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'The Conjuring: Last Rites', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (230, 8.5, '2026-03-19', 140, 160, 148, 'tt39139925', 'After Dakait''s death, Dhurandhar 2 erupts into a ruthless chain of eliminations as a dangerous power vacuum takes hold. Alliances collapse, trust becomes fatal, and every key player turns into a target. Driven by relentless pace over emotion, the film unfolds as a high-stakes survival game-where the only rule is to strike before being struck.', 'https://m.media-amazon.com/images/M/MV5BNzdkNjAxNWMtNWY3My00NTI1LTg2YWQtOGI3MDA0NzdhMjEyXkEyXkFqcGc@._V1_QL75_UY562_CR24,0,380,562_.jpg', 'N/A', null, 'Dhurandhar The Revenge', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (81, 8.3, '1995-11-22', 115, 128, 119, 'tt0114709', 'A little boy named Andy loves to be in his room, playing with his toys, especially his doll named "Woody". But, what do the toys do when Andy is not with them, they come to life. Woody believes that his life (as a toy) is good. However, he must worry about Andy''s family moving, and what Woody does not know is about Andy''s birthday party. Woody does not realize that Andy''s mother gave him an action figure known as Buzz Lightyear, who does not believe that he is a toy, and quickly becomes Andy''s new favorite toy. Woody, who is now consumed with jealousy, tries to get rid of Buzz. Then, both Woody and Buzz are now lost. They must find a way to get back to Andy before he moves without them, but they will have to pass through a ruthless toy killer, Sid Phillips.', 'https://m.media-amazon.com/images/M/MV5BZTA3OWVjOWItNjE1NS00NzZiLWE1MjgtZDZhMWI1ZTlkNzYwXkEyXkFqcGc@._V1_SX300.jpg', 'G', null, 'Toy Story', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (77, 6.3, '2024-04-03', 126, 143, 133, 'tt31159666', 'Sophia, who has been married for a long time with Xavier, invites their young upstairs neighbors to dinner. As the ice is broken, the evening unfolds with a cascade of revelations, laying bare the intricacies of relationships.', 'https://m.media-amazon.com/images/M/MV5BM2I2YzM3MzEtNDk0NS00ZWUzLWJmYjQtMTg1ZGMzYzljZjA5XkEyXkFqcGc@._V1_SX300.jpg', 'N/A', null, 'Maybe More', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (145, 8.7, '1990-09-21', 134, 152, 142, 'tt0099685', 'Henry Hill recounts his life in the mob, from his teenage years to his eventual downfall. Immersed in organized crime, he experiences wealth, power, and violence alongside friends Jimmy Conway and Tommy DeVito. The film blends crime, drama, and dark humor, exploring loyalty, ambition, betrayal, and the consequences of criminal life. Themes of family, morality, and the fleeting nature of power underpin the story.', 'https://m.media-amazon.com/images/M/MV5BN2E5NzI2ZGMtY2VjNi00YTRjLWI1MDUtZGY5OWU1MWJjZjRjXkEyXkFqcGc@._V1_QL75_UX380_CR0,3,380,562_.jpg', 'R', null, 'GoodFellas', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (164, 8, '2017-10-06', 22, 162, 150, 'tt1856101', 'Thirty years after the events of Blade Runner (1982), a new Blade Runner, L.A.P.D. Officer "K" (Ryan Gosling), unearths a long-buried secret that has the potential to plunge what''s left of society into chaos. K''s discovery leads him on a quest to find Rick Deckard (Harrison Ford), a former L.A.P.D. Blade Runner, who has been missing for thirty years.', 'https://m.media-amazon.com/images/M/MV5BNzA1Njg4NzYxOV5BMl5BanBnXkFtZTgwODk5NjU3MzI@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Blade Runner 2049', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (92, 5.8, '2026-01-09', 120, 137, 127, 'tt33028778', 'Looking forward to a relaxing vacation with friends, Lucy returns to her cliffside home in Hawaii after her first year of college. After all, with her father away on business, they have the house all to themselves. However, their reunion takes a dark turn when Ben, the family''s beloved chimpanzee, begins to show strange aggression. As Ben becomes an unpredictable threat to humans, Lucy must find a way to escape the raging primate and survive the night. But what good is fighting back when pinned down by a brutal force of nature?', 'https://m.media-amazon.com/images/M/MV5BMTA5MDI3MjctMGQ1My00ODI1LWFmNjctMjdlNDdiYzcyMWMwXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Primate', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (139, 8.8, '1999-10-15', 123, 140, 130, 'tt0137523', 'A nameless first-person narrator attends support groups in an attempt to subdue his emotional state and relieve his insomniac state. When he meets Marla, another fake attendee of support groups, his life seems to become a little more bearable. However, when he associates himself with Tyler he is dragged into an underground fight club and soap-making scheme. Together the two men spiral out of control and engage in competitive rivalry for love and power.', 'https://m.media-amazon.com/images/M/MV5BOTgyOGQ1NDItNGU3Ny00MjU3LTg2YWEtNmEyYjBiMjI1Y2M5XkEyXkFqcGc@._V1_QL75_UX380_CR0,4,380,562_.jpg', 'R', null, 'Fight Club', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (104, 5.1, '2025-12-05', 129, 146, 136, 'tt30274401', 'One year has passed since the supernatural nightmare at Freddy Fazbear''s Pizza. The stories about what transpired there have been twisted into a campy local legend, inspiring the town''s first ever Fazfest. Former security guard Mike (Josh Hutcherson) and police officer Vanessa (Elizabeth Lail) have kept the truth from Mike''s 11-year-old sister, Abby (Piper Rubio), concerning the fate of her animatronic friends. But when Abby sneaks out to reconnect with Freddy, Bonnie, Chica, and Foxy, it will set into motion a terrifying series of events, revealing dark secrets about the true origin of Freddy''s, and unleashing a long-forgotten horror hidden away for decades.', 'https://m.media-amazon.com/images/M/MV5BZmQ3NmIxNTgtYjFiNS00NzliLWI0YzAtZDkxY2E0YWIxZDEwXkEyXkFqcGc@._V1_QL75_UX380_CR0,20,380,562_.jpg', 'PG-13', null, 'Five Nights at Freddy''s 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (69, 6.8, '2020-06-30', 88, 148, 138, 'tt10474606', 'Grizz, Panda, and Ice Bear embark on an adventure to Canada after an agent from the Department of National Wildlife Control tries to put an end to their hi-jinx.', 'https://m.media-amazon.com/images/M/MV5BMDMwYTQ2MjUtNmE2Yy00NDc5LWIxYjktOTVhNWYxODZhMzYxXkEyXkFqcGc@._V1_SX300.jpg', 'TV-Y7', null, 'We Bare Bears: The Movie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (89, 6.8, '2025-11-21', 136, 154, 144, 'tt31844586', 'A man returns to dismantle his family''s house, where they were murdered in war, to rebuild it elsewhere. When the killer, a Red Army commander, tracks him down, a brutal cross-country pursuit begins.', 'https://m.media-amazon.com/images/M/MV5BM2ZiNDZiZDQtMjYyOC00MWY1LTkyZjgtNDM1MmMwZTdhOWFkXkEyXkFqcGc@._V1_SX300.jpg', 'R', null, 'Sisu: Road to Revenge', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 8.3, '2004-03-19', 137, 156, 145, 'tt0338013', 'Much to his surprise, timid Joel Barish is shocked to discover that the love of his life, sparky Clementine, has had him erased from her memory. To pay her back in the same coin, poor Joel summons up the courage to undergo a painless but intricate medical procedure to do the same, utterly unaware that darkness is an essential part of the light. Now, as hurt and angry Joel''s ugly recollections of Clementine gradually fade away, giving way to a soulless black void, suddenly, he begins having second thoughts, toying with the idea of stopping the irreversible process. In the end, is ignorance really bliss?', 'https://m.media-amazon.com/images/M/MV5BMTY4NzcwODg3Nl5BMl5BanBnXkFtZTcwNTEwOTMyMw@@._V1_SX300.jpg', 'R', null, 'Eternal Sunshine of the Spotless Mind', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (101, 5.6, '2025-04-04', 142, 163, 151, 'tt3566834', 'Four misfits are suddenly pulled through a mysterious portal into a bizarre cubic wonderland that thrives on imagination. To get back home they''ll have to master this world while embarking on a quest with an unexpected expert craf...', 'https://m.media-amazon.com/images/M/MV5BYzFjMzNjOTktNDBlNy00YWZhLWExYTctZDcxNDA4OWVhOTJjXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'A Minecraft Movie', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (100, 7.8, '2009-02-06', 128, 145, 135, 'tt0327597', 'When Coraline moves to an old house, she feels bored and neglected by her parents. She finds a hidden door with a bricked up passage. During the night, she crosses the passage and finds a parallel world where everybody has buttons instead of eyes, with caring parents and all her dreams coming true. When the Other Mother invites Coraline to stay in her world forever, the girl refuses and finds that the alternate reality where she is trapped is only a trick to lure her.', 'https://m.media-amazon.com/images/M/MV5BMzQxNjM5NzkxNV5BMl5BanBnXkFtZTcwMzg5NDMwMg@@._V1_SX300.jpg', 'PG', null, 'Coraline', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (99, 6.2, '2026-01-23', 135, 153, 143, 'tt31050594', 'Set in the near future, a detective accused of murdering his wife has 90 minutes to prove his innocence to an advanced AI judge.', 'https://m.media-amazon.com/images/M/MV5BMWJmYjcwMTMtMDU1ZC00ZGI5LTlmZDAtODI3NDA2ZTE5ZGVlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG-13', null, 'Mercy', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (95, 6.4, '2025-08-29', 138, 157, 146, 'tt35222590', 'A man trapped in a endless sterile subway passageway sets out to find Exit 8. The rules of his quest are simple: do not overlook anything out of the ordinary. If you discover an anomaly, turn back immediately. If you don''t, carry on. Then leave from Exit 8. But even a single oversight will send him back to the beginning. Will he ever reach his goal and escape this infinite corridor?', 'https://m.media-amazon.com/images/M/MV5BM2RjMTZkZjktYjY5MC00Njk4LTlmZjgtZDRjMTBiMTY2MzdhXkEyXkFqcGc@._V1_QL75_UX380_CR0,14,380,562_.jpg', 'PG-13', null, 'Exit 8', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (108, 7.4, '2025-11-26', 139, 159, 147, 'tt26443597', 'Officers Judy Hopps and Nick Wilde are still fighting to be taken seriously as detectives - a struggle that gets worse when their off-the-books smuggling probe turns into a public disaster. With Chief Bogo threatening to split them up, the pair chase one last lead: a mysterious snake seen near the crime scene. That trail leads them to Gary DeSnake, a pit viper fugitive obsessed with exposing a secret behind the city''s climate-controlling weather walls. When Judy and Nick realize he''s telling the truth, they''re suddenly framed by the powerful Lynxley family, whose buried crimes drove Zootopia''s reptiles underground - and whose new plans are far more sinister. Branded fugitives, Judy and Nick join forces with eccentric beaver conspiracy buff Nibbles Maplestick to track down Gary and uncover the city''s founding injustice - a case that will test their partnership, upend everything they thought they knew about Zootopia, and turn friends and enemies upside-down.', 'https://m.media-amazon.com/images/M/MV5BYjg1Mjc3MjQtMTZjNy00YWVlLWFhMWEtMWI3ZTgxYjJmNmRlXkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'PG', null, 'Zootopia 2', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (134, 7, '2026-02-13', 143, 164, 152, 'tt1341338', 'A man, armed with a bomb, takes over a diner. He claims he is from the future and is here to correct a massive technological error that will doom humanity. He knows what he needs to do prevent the error but needs to gather together a suitable group from the diner to help him in his mission.', 'https://m.media-amazon.com/images/M/MV5BOTQ0NzYzM2QtOWYzMC00MGU5LWJmMTQtYTU1ODU0ZjUwYjk0XkEyXkFqcGc@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'Good Luck, Have Fun, Don''t Die', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (140, 8.5, '2023-06-02', 144, 165, 153, 'tt9362722', 'Miles Morales returns for the next chapter of the Oscar®-winning Spider-Verse saga, an epic adventure that will transport Brooklyn''s full-time, friendly neighborhood Spider-Man across the Multiverse to join forces with Gwen Stacy and a new team of Spider-People to face off with a villain more powerful than anything they have ever encountered.', 'https://m.media-amazon.com/images/M/MV5BNThiZjA3MjItZGY5Ni00ZmJhLWEwN2EtOTBlYTA4Y2E0M2ZmXkEyXkFqcGc@._V1_SX300.jpg', 'PG', null, 'Spider-Man: Across the Spider-Verse', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (112, 8.5, '2011-11-02', 146, 166, 154, 'tt1675434', 'Philippe, a wealthy quadriplegic, hires Driss, an ex-convict, as his caregiver. Despite cultural and social differences, the two form a deep friendship that transforms their lives. Through humor, empathy, and mutual respect, they navigate physical, emotional, and social challenges. The film explores friendship, personal growth, and human dignity, blending comedy and drama to highlight the transformative power of connection and understanding across divides.', 'https://m.media-amazon.com/images/M/MV5BMTYxNDA3MDQwNl5BMl5BanBnXkFtZTcwNTU4Mzc1Nw@@._V1_QL75_UX380_CR0,0,380,562_.jpg', 'R', null, 'The Intouchables', null);
INSERT INTO public.movies (duration_in_minutes, rating, release_date, director_id, id, writer_id, imdb_id, plot, poster, rated, synopsis, title, video_url) VALUES (88, 5.8, '2026-03-25', 145, 167, 155, 'tt26678938', 'An action-packed thriller where five ballerinas, on their way to a prestigious dance competition, are barely on speaking terms when their bus breaks down in a remote forest. With no other options, they reluctantly seek shelter at an unsettling roadside inn run by Devora Kasimer, a reclusive former ballet prodigy. From the moment they arrive, something feels wrong--and their worst instincts prove right. As the situation turns deadly, the fractured team must set aside rivalries and weaponize years of brutal training, turning grace, discipline, and even pointe shoes into tools for survival.', 'https://m.media-amazon.com/images/M/MV5BMTRmMTE4MmYtOWRmNi00ZDJjLWFmY2UtNTliMzlkNTUzNDRjXkEyXkFqcGc@._V1_QL75_UX380_CR0,57,380,562_.jpg', 'R', null, 'Pretty Lethal', null);
